var e={},t=JSON.parse(`{"e100":{"name":"Curcumina","note":"Colorante natural de la cúrcuma.","detail":{"risks":"El pigmento amarillo de la raíz de cúrcuma, utilizado desde hace milenios en la cocina. El cuerpo lo absorbe mal y lo excreta en gran medida sin cambios.","benefits":"","interestingFact":"","research":""}},"e101":{"name":"Riboflavina","note":"Vitamina B2 utilizada como colorante.","detail":{"risks":"Una vitamina que cumple una doble función como colorante amarillo: la misma riboflavina que tu cuerpo utiliza para convertir los alimentos en energía.","benefits":"","interestingFact":"","research":""}},"e102":{"name":"Tartracina","note":"Colorante azoico vinculado a la hiperactividad infantil; requiere etiqueta de advertencia en la EU.","detail":{"risks":"Un colorante azoico sintético. Uno de los seis colores de «Southampton» que el ensayo de Lancet 2007 vinculó con un aumento de la hiperactividad en niños; los productos de la EU que lo contienen deben llevar una etiqueta de advertencia.","benefits":"","interestingFact":"","research":""}},"e104":{"name":"Amarillo de quinoleína","note":"Colorante sintético vinculado a la hiperactividad; requiere etiqueta de advertencia en la EU.","detail":{"risks":"Un amarillo sintético restringido en la EU tras los hallazgos de Southampton; prohibido en alimentos en EE. UU., Canadá y Japón.","benefits":"","interestingFact":"","research":""}},"e110":{"name":"Amarillo ocaso","note":"Colorante azoico vinculado a la hiperactividad infantil; requiere etiqueta de advertencia en la EU.","detail":{"risks":"Un colorante azoico derivado del petróleo del grupo de los «seis de Southampton». La EFSA redujo drásticamente su ingesta diaria admisible en 2009 antes de flexibilizarla parcialmente tras nuevos datos.","benefits":"","interestingFact":"","research":""}},"e120":{"name":"Cochinilla (carmín)","note":"Rojo derivado de insectos; puede desencadenar reacciones alérgicas.","detail":{"risks":"Un rojo intenso extraído de cochinillas secas: se necesitan aproximadamente 70,000 insectos para obtener 500 g de colorante. Es natural, pero es uno de los pocos colorantes con reacciones alérgicas documentadas (ocasionalmente graves).","benefits":"","interestingFact":"","research":""}},"e122":{"name":"Azorrubina","note":"Colorante azoico vinculado a la hiperactividad; requiere etiqueta de advertencia en la EU.","detail":{"risks":"Un colorante azoico sintético prohibido en EE. UU. y en varios otros países; los productos de la EU necesitan una etiqueta de advertencia sobre hiperactividad.","benefits":"","interestingFact":"","research":""}},"e124":{"name":"Ponceau 4R","note":"Colorante azoico vinculado a la hiperactividad; requiere etiqueta de advertencia en la EU.","detail":{"risks":"Un colorante azoico de color rojo fresa del grupo de los «seis de Southampton», prohibido en EE. UU. La EFSA redujo cuatro veces su ingesta admisible en 2009.","benefits":"","interestingFact":"","research":""}},"e129":{"name":"Rojo Allura","note":"Colorante azoico vinculado a la hiperactividad; requiere etiqueta de advertencia en la EU.","detail":{"risks":"El colorante rojo más utilizado en EE. UU., aunque la etiqueta de advertencia por hiperactividad es obligatoria en la EU. Estudios recientes en ratones también debaten efectos de inflamación intestinal a dosis altas.","benefits":"","interestingFact":"","research":""}},"e131":{"name":"Azul patente V","note":"Azul sintético; reacciones alérgicas poco frecuentes.","detail":{"risks":"Un colorante sintético que también se utiliza en medicina para marcar ganglios linfáticos durante cirugías, que es donde se documentó por primera vez su raro potencial alérgico.","benefits":"","interestingFact":"","research":""}},"e132":{"name":"Indigotina","note":"Azul sintético, generalmente bien tolerado.","detail":{"risks":"El primo sintético del índigo, el tinte que da color a los pantalones vaqueros. Se absorbe mal; la EFSA no encontró problemas de seguridad con las ingestas notificadas.","benefits":"","interestingFact":"","research":""}},"e133":{"name":"Azul brillante","note":"Colorante sintético; generalmente bien tolerado en dosis alimentarias.","detail":{"risks":"Un azul de triarilmetano que a menudo se combina con tartracina para obtener tonos verdes. Se absorbe menos del 5%; el resto pasa de largo por el organismo.","benefits":"","interestingFact":"","research":""}},"e140":{"name":"Clorofilas","note":"Pigmento verde natural de las plantas.","detail":{"risks":"La misma molécula que da color verde a las hojas e impulsa la fotosíntesis, extraída de hierba, ortigas o alfalfa.","benefits":"","interestingFact":"","research":""}},"e141":{"name":"Clorofilinas de cobre","note":"Pigmento verde natural estabilizado.","detail":{"risks":"Clorofila a la que se le ha cambiado el núcleo de magnesio por cobre, lo que mantiene el verde estable durante el calentamiento; el cobre permanece unido y sin absorber.","benefits":"","interestingFact":"","research":""}},"e142":{"name":"Verde S","note":"Verde sintético, restringido en varios países.","detail":{"risks":"Un colorante sintético permitido en la EU (salsa de menta, guisantes en conserva), pero prohibido en Canadá, Japón y Noruega. Se absorbe mal.","benefits":"","interestingFact":"","research":""}},"e150a":{"name":"Caramelo simple","note":"Colorante caramelo simple; la clase de caramelo que menos preocupa.","detail":{"risks":"Elaborado calentando azúcar, de forma muy parecida a caramelizarlo en una sartén, solo que bajo control industrial. Es la única clase de caramelo fabricada sin química de amoníaco ni sulfitos.","benefits":"","interestingFact":"","research":""}},"e150b":{"name":"Caramelo de sulfito cáustico","note":"Caramelo elaborado con compuestos de sulfito.","detail":{"risks":"Caramelo producido con compuestos de sulfito, utilizado en bebidas espirituosas como el whisky y el brandi. El sulfito residual es insignificante.","benefits":"","interestingFact":"","research":""}},"e150c":{"name":"Caramelo amónico","note":"Contiene trazas de 4-MEI, objeto de debate con ingestas elevadas.","detail":{"risks":"Caramelo elaborado con compuestos de amonio; el proceso crea trazas de 4-metilimidazol (4-MEI), que causó tumores en estudios con ratones a dosis altas. La EFSA considera seguras las ingestas habituales, pero fijó límites.","benefits":"","interestingFact":"","research":""}},"e150d":{"name":"Caramelo de sulfito amónico","note":"Caramelo de cola; contiene trazas de 4-MEI, objeto de debate con ingestas elevadas.","detail":{"risks":"El colorante más consumido del mundo por volumen: da el color marrón a las bebidas de cola. Mismo debate sobre el 4-MEI que con el E150c; California exige advertencias sobre el cáncer por encima de ciertos niveles, mientras que la EFSA considera seguro el consumo normal.","benefits":"","interestingFact":"","research":""}},"e153":{"name":"Carbón vegetal","note":"Colorante negro; revisado por la EU, debate sobre nanopartículas.","detail":{"risks":"Esencialmente carbón vegetal de grado alimentario. La EFSA señaló que algunos lotes contienen nanopartículas lo suficientemente pequeñas como para ser absorbidas, lo que motivó una revisión continua de su pureza.","benefits":"","interestingFact":"","research":""}},"e155":{"name":"Marrón HT","note":"Marrón azoico, prohibido en varios países.","detail":{"risks":"Un marrón azoico sintético utilizado en pasteles de chocolate; prohibido en EE. UU., Canadá y gran parte de Escandinavia, pero permitido en la EU dentro de ciertos límites.","benefits":"","interestingFact":"","research":""}},"e160a":{"name":"Carotenos","note":"Pigmento naranja natural, provitamina A.","detail":{"risks":"El pigmento de las zanahorias y las calabazas; tu cuerpo lo convierte en vitamina A según lo necesita, almacenando el exceso de forma inofensiva en la grasa (si comes lo suficiente, la piel se vuelve literalmente naranja).","benefits":"","interestingFact":"","research":""}},"e160b":{"name":"Achiote","note":"Colorante natural de semillas; reacciones de sensibilidad poco frecuentes.","detail":{"risks":"Un extracto rojo anaranjado de las semillas del árbol del achiote, utilizado por los aztecas como pintura corporal y ahora para colorear el cheddar y el Red Leicester. Se han documentado reacciones raras de hipersensibilidad.","benefits":"","interestingFact":"","research":""}},"e160c":{"name":"Extracto de pimentón","note":"Colorante natural derivado del pimiento.","detail":{"risks":"Pigmento concentrado de pimientos rojos dulces: la misma capsantina que vuelve rojo al pimentón, pero sin el picante.","benefits":"","interestingFact":"","research":""}},"e160d":{"name":"Licopeno","note":"Pigmento natural del tomate.","detail":{"risks":"El rojo de los tomates y la sandía; también se ha estudiado como antioxidante por derecho propio.","benefits":"","interestingFact":"","research":""}},"e161b":{"name":"Luteína","note":"Pigmento natural de la caléndula.","detail":{"risks":"Un carotenoide amarillo procedente de los pétalos de caléndula, idéntico a la luteína concentrada en la retina del ojo.","benefits":"","interestingFact":"","research":""}},"e162":{"name":"Rojo de remolacha","note":"Pigmento natural de la remolacha.","detail":{"risks":"Betanina, exprimida de las remolachas. Tan inofensiva que su principal «efecto secundario» es el mismo que tienen las remolachas.","benefits":"","interestingFact":"","research":""}},"e163":{"name":"Antocianinas","note":"Pigmentos naturales de bayas y uvas.","detail":{"risks":"La familia de pigmentos de color rojo purpúreo de la piel de la uva, las bayas y la col lombarda. Cambian de color según la acidez (rojo en medio ácido, azul en alcalino), motivo por el cual el mismo aditivo puede verse diferente según el producto.","benefits":"","interestingFact":"","research":""}},"e170":{"name":"Carbonato de calcio","note":"Tiza: blanco mineral, también es una fuente de calcio.","detail":{"risks":"Tiza o piedra caliza común, utilizada como colorante de superficie blanco y antiaglomerante. Es el mismo compuesto que el suplemento de calcio.","benefits":"","interestingFact":"","research":""}},"e171":{"name":"Dióxido de titanio","note":"Prohibido en alimentos en la EU desde 2022: no se pudo descartar la genotoxicidad.","detail":{"risks":"Un pigmento mineral blanco brillante (presente también en pinturas y protectores solares). La EFSA ya no pudo descartar el daño al ADN derivado de la acumulación de nanopartículas, y la EU lo prohibió en los alimentos en 2022 (sigue siendo legal en EE. UU.).","benefits":"","interestingFact":"","research":""}},"e172":{"name":"Óxidos de hierro","note":"Pigmentos minerales (tonos de óxido).","detail":{"risks":"Óxido de hierro purificado (químicamente, óxido controlado) que aporta tonos amarillos, rojos y negros. Prácticamente insoluble e inabsorbible.","benefits":"","interestingFact":"","research":""}},"e173":{"name":"Aluminio","note":"Color metálico de superficie; preocupación por la ingesta de aluminio.","detail":{"risks":"Aluminio metálico para decoración plateada. Contribuye al aluminio dietético total, para el cual la EFSA mantiene un límite semanal estricto porque se acumula en el cuerpo.","benefits":"","interestingFact":"","research":""}},"e174":{"name":"Plata","note":"Color metálico decorativo.","detail":{"risks":"Pan de plata real, utilizado principalmente en repostería (las bolitas plateadas de las tartas). Inerte en el intestino a dosis decorativas.","benefits":"","interestingFact":"","research":""}},"e175":{"name":"Oro","note":"Color metálico decorativo.","detail":{"risks":"Pan de oro real. Químicamente inerte: pasa de largo por completo, lo que lo convierte en el aditivo más caro que no hace absolutamente nada.","benefits":"","interestingFact":"","research":""}},"e200":{"name":"Ácido sórbico","note":"Conservante suave; reacciones cutáneas ocasionales.","detail":{"risks":"Aislado por primera vez de las bayas del serbal; bloquea el crecimiento de mohos y levaduras al alterar sus enzimas. Tu cuerpo lo metaboliza como un ácido graso.","benefits":"","interestingFact":"","research":""}},"e201":{"name":"Sorbato sódico","note":"Sal del ácido sórbico, conservante suave.","detail":{"risks":"La forma sódica del ácido sórbico (originalmente presente en las bayas de serbal). Se disuelve mejor en alimentos acuosos y funciona de manera idéntica: bloqueando las enzimas de mohos y levaduras.","benefits":"","interestingFact":"","research":""}},"e202":{"name":"Sorbato potásico","note":"Conservante suave común.","detail":{"risks":"El conservante estrella del queso, el vino y los productos de panadería: una sal más soluble del ácido sórbico (procedente originalmente de las bayas de serbal). Entre los conservantes conocidos, es uno de los mejor tolerados.","benefits":"","interestingFact":"","research":""}},"e203":{"name":"Sorbato cálcico","note":"Sal del ácido sórbico, conservante suave.","detail":{"risks":"La forma cálcica del ácido sórbico, utilizada cuando se requiere un conservante sin sodio. Se metaboliza como un ácido graso, igual que el resto de la familia de los sorbatos.","benefits":"","interestingFact":"","research":""}},"e210":{"name":"Ácido benzoico","note":"Puede formar benceno con la vitamina C; desencadenante de alergias.","detail":{"risks":"Se encuentra de forma natural en los arándanos rojos y la canela; frena las levaduras y bacterias en alimentos ácidos. El inconveniente: combinado con vitamina C en refrescos puede formar trazas de benceno, un carcinógeno conocido, motivo por el cual se reformularon las recetas en la década de 2000.","benefits":"","interestingFact":"","research":""}},"e211":{"name":"Benzoato sódico","note":"Puede formar benceno con la vitamina C; vinculado a la hiperactividad en combinación con colorantes.","detail":{"risks":"La sal soluble del ácido benzoico, un estándar en refrescos. El estudio de Southampton lo probó junto con colorantes azoicos y halló efectos en la hiperactividad en combinación; el problema del benceno con la vitamina C también se aplica aquí.","benefits":"","interestingFact":"","research":""}},"e212":{"name":"Benzoato potásico","note":"Conservante benzoato; misma preocupación de benceno/vitamina C.","detail":{"risks":"La forma potásica del benzoato de sodio, elegida para recetas bajas en sodio. Misma química: eficaz contra las levaduras en bebidas ácidas y la misma precaución de formación de benceno con la vitamina C.","benefits":"","interestingFact":"","research":""}},"e213":{"name":"Benzoato cálcico","note":"Conservante benzoato; misma preocupación de benceno/vitamina C.","detail":{"risks":"La forma cálcica de la familia de los benzoatos, de uso poco frecuente. Comparte las características de la familia: solo funciona en alimentos ácidos y conlleva la precaución de la vitamina C/benceno.","benefits":"","interestingFact":"","research":""}},"e214":{"name":"Etilparabeno","note":"Conservante parabeno; debate endocrino.","detail":{"risks":"Uno de los pocos parabenos que todavía se permiten en los alimentos (rara vez utilizado). Los parabenos imitan débilmente los estrógenos en estudios de laboratorio, lo que los mantiene bajo supervisión endocrina.","benefits":"","interestingFact":"","research":""}},"e218":{"name":"Metilparabeno","note":"Conservante parabeno; debate endocrino.","detail":{"risks":"Un conservante parabeno más conocido en la cosmética, que en ocasiones se utiliza en coberturas de confitería. La cuestión endocrina —la débil imitación de los estrógenos en estudios de laboratorio— se aplica a toda la familia de los parabenos.","benefits":"","interestingFact":"","research":""}},"e219":{"name":"Metilparabeno sódico","note":"Conservante parabeno; debate endocrino.","detail":{"risks":"La sal sódica soluble en agua del metilparabeno. Misma familia, misma supervisión endocrina.","benefits":"","interestingFact":"","research":""}},"e220":{"name":"Dióxido de azufre","note":"Sulfito: un alérgeno importante, destruye la vitamina B1.","detail":{"risks":"El antiguo conservante del vino: los romanos quemaban velas de azufre en los barriles. Evita el oscurecimiento y los microbios, pero es un alérgeno real: alrededor del 3–10% de los asmáticos reaccionan, razón por la cual la mención \\"contiene sulfitos\\" es un etiquetado obligatorio. También destruye la tiamina (vitamina B1) en los alimentos.","benefits":"","interestingFact":"","research":""}},"e221":{"name":"Sulfito sódico","note":"Alérgeno sulfito.","detail":{"risks":"Una sal de sulfito que libera el mismo SO₂ activo que el E220: mismo poder antimicrobiano, misma precaución de sensibilidad en asmáticos y mismo etiquetado obligatorio de alérgenos.","benefits":"","interestingFact":"","research":""}},"e222":{"name":"Bisulfito sódico","note":"Alérgeno sulfito.","detail":{"risks":"Un miembro de la familia de los sulfitos utilizado en el vino y los alimentos encurtidos. Todos los sulfitos comparten la precaución respecto a los alérgenos y la destrucción de la vitamina B1 del E220.","benefits":"","interestingFact":"","research":""}},"e223":{"name":"Metabisulfito sódico","note":"Alérgeno sulfito.","detail":{"risks":"La forma en polvo de la química del dióxido de azufre, común en frutos secos y vino. Misma precaución respecto a alérgenos que el E220: los orejones de albaricoque se mantienen naranjas gracias a él.","benefits":"","interestingFact":"","research":""}},"e224":{"name":"Metabisulfito potásico","note":"Alérgeno sulfito.","detail":{"risks":"La \\"pastilla Campden\\" de los elaboradores de vino: el sulfito estándar para el vino casero y comercial. Mismas precauciones sobre alérgenos y vitamina B1 que el resto de la familia.","benefits":"","interestingFact":"","research":""}},"e226":{"name":"Sulfito cálcico","note":"Alérgeno sulfito.","detail":{"risks":"Una sal cálcica de la familia de los sulfitos rara vez utilizada; comparte la precaución del grupo sobre la sensibilidad en asmáticos y el etiquetado obligatorio.","benefits":"","interestingFact":"","research":""}},"e228":{"name":"Bisulfito potásico","note":"Alérgeno sulfito.","detail":{"risks":"Un sulfito utilizado principalmente en el vino. Misma química familiar y precaución respecto a alérgenos que el E220.","benefits":"","interestingFact":"","research":""}},"e234":{"name":"Nisina","note":"Péptido antibacteriano natural procedente de la fermentación.","detail":{"risks":"Un péptido producido por las mismas bacterias que fermentan la leche: perfora la membrana de las bacterias responsables del deterioro. Se utiliza en quesos y conservas; se digiere como cualquier otra proteína.","benefits":"","interestingFact":"","research":""}},"e235":{"name":"Natamicina","note":"Antifúngico para la corteza del queso; debate sobre la clase de antibióticos.","detail":{"risks":"Un antifúngico procedente de bacterias del suelo, con el que se pincelan las cortezas de queso y las tripas de embutidos secos. Apenas se absorbe, pero su uso médico como antifúngico mantiene vivo el debate sobre las resistencias.","benefits":"","interestingFact":"","research":""}},"e239":{"name":"Hexametilentetramina","note":"Conservante liberador de formaldehído (solo Provolone).","detail":{"risks":"Permitido en la EU únicamente para el queso Provolone. Funciona liberando formaldehído lentamente, motivo por el cual su uso está tan estrictamente limitado.","benefits":"","interestingFact":"","research":""}},"e242":{"name":"Dicarbonato de dimetilo","note":"Esterilizante de bebidas que se descompone por completo.","detail":{"risks":"Inyectado en las bebidas justo antes del embotellado, destruye los microbios y luego se hidroliza por completo en diminutas cantidades de metanol y CO₂ en cuestión de horas; no queda nada para cuando te lo bebes.","benefits":"","interestingFact":"","research":""}},"e249":{"name":"Nitrito potásico","note":"Nitrito para carnes curadas; forma nitrosaminas, vía clasificada por la IARC.","detail":{"risks":"El gemelo de potasio del nitrito de sodio (E250): mantiene la carne curada rosada y libre de botulismo, pero alimenta la misma química de nitrosaminas que fundamenta la clasificación de la IARC para la carne procesada.","benefits":"","interestingFact":"","research":""}},"e250":{"name":"Nitrito sódico","note":"Nitrito para carnes curadas; forma nitrosaminas carcinógenas (IARC).","detail":{"risks":"Lo que le da al jamón su color rosado y bloquea el botulismo —la toxina más letal conocida—, razón por la cual todavía está permitido. Sin embargo, con las proteínas de la carne y el calor forma nitrosaminas, aspecto central por el cual la IARC clasifica la carne procesada como carcinógena para los humanos. Francia comenzó a restringirlo en 2023.","benefits":"","interestingFact":"","research":""}},"e251":{"name":"Nitrato sódico","note":"Se convierte en nitrito; misma preocupación por las nitrosaminas.","detail":{"risks":"La forma de almacenamiento de la química del curado: las bacterias de la carne (y de tu saliva) convierten constantemente el nitrato en nitrito, alimentando la misma vía de las nitrosaminas que el E250.","benefits":"","interestingFact":"","research":""}},"e252":{"name":"Nitrato potásico","note":"Se convierte en nitrito; misma preocupación por las nitrosaminas.","detail":{"risks":"Salitre: utilizado para curar carne desde la Edad Media (y para hacer pólvora). Las bacterias lo convierten en nitrito en la carne, donde comienza la química de las nitrosaminas.","benefits":"","interestingFact":"","research":""}},"e260":{"name":"Ácido acético","note":"Vinagre.","detail":{"risks":"Ácido concentrado de vinagre. Uno de los conservantes más antiguos de la historia de la humanidad.","benefits":"","interestingFact":"","research":""}},"e261":{"name":"Acetato potásico","note":"Sal de vinagre.","detail":{"risks":"El ácido del vinagre unido al potasio: un regulador de la acidez que tu cuerpo trata exactamente igual que al vinagre.","benefits":"","interestingFact":"","research":""}},"e262":{"name":"Acetatos de sodio","note":"Sal de vinagre: el sabor de las patatas fritas de sal y vinagre.","detail":{"risks":"El acetato de sodio es lo que le da a las patatas fritas de sal y vinagre su toque ácido sin humedecerlas. También es el compuesto que contienen los calentadores de manos reutilizables.","benefits":"","interestingFact":"","research":""}},"e263":{"name":"Acetato cálcico","note":"Sal de vinagre.","detail":{"risks":"Ácido de vinagre unido al calcio; funciona también como agente reafirmante. Se metaboliza como el vinagre.","benefits":"","interestingFact":"","research":""}},"e270":{"name":"Ácido láctico","note":"Ácido de fermentación natural.","detail":{"risks":"El ácido del yogur, la masa madre y las agujetas: producido por fermentación. El ácido láctico de grado alimentario procede de fermentar azúcar con la misma familia de bacterias que la del yogur.","benefits":"","interestingFact":"","research":""}},"e280":{"name":"Ácido propiónico","note":"Conservante para el pan; debate sobre efectos intestinales a dosis altas.","detail":{"risks":"Se encuentra de forma natural en el queso suizo (aporta sabor a los agujeros) y en tu propio intestino, donde las bacterias lo producen a partir de la fibra. Como conservante del pan frena el moho; pequeños estudios debaten sus efectos metabólicos a dosis altas.","benefits":"","interestingFact":"","research":""}},"e281":{"name":"Propionato sódico","note":"Inhibidor de moho en el pan.","detail":{"risks":"La sal sódica del ácido propiónico: el compuesto que tus propias bacterias intestinales producen a partir de la fibra, aquí manteniendo el pan de molde libre de moho durante semanas.","benefits":"","interestingFact":"","research":""}},"e282":{"name":"Propionato cálcico","note":"Conservante para el pan; debate sobre efectos intestinales a dosis altas.","detail":{"risks":"El conservante del pan más común en todo el mundo. Químicamente es el mismo propionato que tu intestino produce a partir de la fibra; unos pocos estudios reducidos debaten sus efectos en el apetito y el metabolismo a ingestas elevadas.","benefits":"","interestingFact":"","research":""}},"e283":{"name":"Propionato potásico","note":"Inhibidor de moho en el pan.","detail":{"risks":"La forma potásica de la familia de los propionatos, para panes bajos en sodio. Mismo mecanismo de bloqueo del moho.","benefits":"","interestingFact":"","research":""}},"e284":{"name":"Ácido bórico","note":"Permitido únicamente para el caviar en la EU.","detail":{"risks":"Un antiguo conservante ahora prohibido en todos los alimentos de la EU excepto en uno: el caviar real de esturión, donde ninguna alternativa conserva las huevas. Restringido debido a que el boro se acumula.","benefits":"","interestingFact":"","research":""}},"e285":{"name":"Bórax","note":"Permitido únicamente para el caviar en la EU.","detail":{"risks":"La sal sódica del ácido bórico, que comparte su única exención en la EU: el caviar de esturión. En todos los demás ámbitos es un ingrediente de productos de limpieza, no un ingrediente alimentario.","benefits":"","interestingFact":"","research":""}},"e290":{"name":"Dióxido de carbono","note":"Las burbujas de las bebidas con gas.","detail":{"risks":"Simplemente CO₂ — el mismo gas que exhalas. En las bebidas se disuelve como ácido carbónico, creando las burbujas y el cosquilleo en la lengua; en los envases desplaza al oxígeno para que los alimentos se estropeen más despacio. Abandona tu cuerpo con un eructo.","benefits":"","interestingFact":"","research":""}},"e296":{"name":"Ácido málico","note":"Ácido natural de las frutas.","detail":{"risks":"El ácido agrio de las manzanas verdes; su nombre procede de malum, manzana en latín. También es el toque ácido extremo de los caramelos ultraácidos.","benefits":"","interestingFact":"","research":""}},"e297":{"name":"Ácido fumárico","note":"Ácido natural de tipo frutal.","detail":{"risks":"Se encuentra de forma natural en los hongos boletus y en los líquenes; se utiliza donde el ácido málico o el cítrico absorberían demasiada humedad, por ejemplo, en mezclas en polvo.","benefits":"","interestingFact":"","research":""}},"e300":{"name":"Ácido ascórbico","note":"Vitamina C.","detail":{"risks":"Vitamina C pura. En los alimentos actúa como un captador de oxígeno: se sacrifica a la oxidación para que el alimento no se oscurezca. En el pan, refuerza el gluten.","benefits":"","interestingFact":"","research":""}},"e301":{"name":"Ascorbato sódico","note":"Sal de la vitamina C.","detail":{"risks":"Vitamina C unida al sodio para una mejor solubilidad; es habitual en los embutidos y carnes curadas, donde acelera el curado y suprime la formación de nitrosaminas.","benefits":"","interestingFact":"","research":""}},"e302":{"name":"Ascorbato cálcico","note":"Sal de la vitamina C.","detail":{"risks":"Vitamina C en su forma cálcica más suave, utilizada para evitar que la fruta cortada se oscurezca. Nutricionalmente, sigue siendo solo vitamina C con un poco de calcio.","benefits":"","interestingFact":"","research":""}},"e304":{"name":"Palmitato de ascorbilo","note":"Vitamina C liposoluble.","detail":{"risks":"Vitamina C unida a un ácido graso para poder proteger aceites y grasas del enranciamiento, allí donde la vitamina C habitual no puede llegar.","benefits":"","interestingFact":"","research":""}},"e306":{"name":"Tocoferoles","note":"Vitamina E.","detail":{"risks":"Vitamina E natural extraída de aceites vegetales; protege las grasas para que no se enrancien del mismo modo que protege tus membranas celulares.","benefits":"","interestingFact":"","research":""}},"e307":{"name":"Alfa-tocoferol","note":"Vitamina E.","detail":{"risks":"La forma específica de vitamina E que prefiere tu cuerpo, elaborada sintéticamente para mayor consistencia. Misma función antioxidante que el E306.","benefits":"","interestingFact":"","research":""}},"e308":{"name":"Gamma-tocoferol","note":"Vitamina E.","detail":{"risks":"La forma de vitamina E más común en el aceite de soja y de maíz, que protege las grasas de la oxidación.","benefits":"","interestingFact":"","research":""}},"e309":{"name":"Delta-tocoferol","note":"Vitamina E.","detail":{"risks":"El más termoestable de la familia de la vitamina E, preferido para grasas de fritura.","benefits":"","interestingFact":"","research":""}},"e310":{"name":"Galato de propilo","note":"Antioxidante sintético; debate endocrino.","detail":{"risks":"Un antioxidante sintético para grasas y aceites. Estudios en roedores plantearon dudas (disputadas) sobre efectos endocrinos y tumorales; la EFSA reajustó su límite de ingesta en 2014 y cada vez aparece menos en las recetas modernas.","benefits":"","interestingFact":"","research":""}},"e311":{"name":"Galato de octilo","note":"Antioxidante sintético; datos limitados.","detail":{"risks":"Un antioxidante del grupo de los galatos cuya autorización en la EU caducó en 2018 por falta de datos de seguridad; encontrarlo en una etiqueta suele significar una formulación antigua o una importación.","benefits":"","interestingFact":"","research":""}},"e312":{"name":"Galato de dodecilo","note":"Antioxidante sintético; datos limitados.","detail":{"risks":"El galato de cadena más larga; al igual que el E311, su autorización en la EU se retiró en 2018 cuando los fabricantes no presentaron datos que lo respaldaran.","benefits":"","interestingFact":"","research":""}},"e315":{"name":"Ácido eritórbico","note":"Molécula espejo de la vitamina C, solo antioxidante.","detail":{"risks":"Un isómero especular de la vitamina C: mismo poder antioxidante en los alimentos, pero casi sin actividad vitamínica en el cuerpo.","benefits":"","interestingFact":"","research":""}},"e316":{"name":"Eritorbato sódico","note":"Antioxidante utilizado en carnes curadas.","detail":{"risks":"Acelera el curado y reduce el nitrito necesario en la carne procesada: su presencia suele significar menos nitritos, no más riesgo. El viejo mito de que \\"se elabora con lombrices de tierra\\" es exactamente eso, un mito (se produce a partir de azúcar).","benefits":"","interestingFact":"","research":""}},"e319":{"name":"TBHQ","note":"Antioxidante sintético; estudios sobre efectos inmunitarios en debate.","detail":{"risks":"Terbutilhidroquinona, un antioxidante derivado del petróleo presente en aceites de fritura y fideos instantáneos. Estudios en animales con dosis altas debaten efectos inmunitarios y tumorales; la EFSA mantiene un límite de ingesta estricto.","benefits":"","interestingFact":"","research":""}},"e320":{"name":"BHA","note":"Posible carcinógeno (IARC 2B); preocupación endocrina.","detail":{"risks":"Butilhidroxianisol, un antioxidante sintético. La IARC lo clasifica como \\"posiblemente carcinógeno\\" a partir de tumores en el preestómago de roedores; también está en la lista de evaluación de alteradores endocrinos de la EU. La vitamina E realiza la misma función.","benefits":"","interestingFact":"","research":""}},"e321":{"name":"BHT","note":"Carcinogenicidad y efectos endocrinos en debate.","detail":{"risks":"El hermano químico del BHA, utilizado también en cosméticos y combustible para aviones. La evidencia es más mixta que para el BHA —algunos estudios sugieren incluso efectos protectores—, pero el debate endocrino hace que permanezca bajo alerta.","benefits":"","interestingFact":"","research":""}},"e322":{"name":"Lecitinas","note":"Emulsionante natural de soja o girasol.","detail":{"risks":"La molécula que permite que la grasa y el agua se mezclen: un extremo ama el agua, el otro ama el aceite. Se extrae de las habas de soja, las semillas de girasol o la yema de huevo (la mayonesa funciona gracias a la lecitina del huevo). Tus propias membranas celulares están construidas en parte con ella.","benefits":"","interestingFact":"","research":""}},"e325":{"name":"Lactato sódico","note":"Sal del ácido láctico.","detail":{"risks":"Ácido de fermentación unido al sodio: un retenedor de humedad y conservante suave en carnes y repostería. Tus músculos producen el mismo lactato durante el ejercicio.","benefits":"","interestingFact":"","research":""}},"e326":{"name":"Lactato potásico","note":"Sal del ácido láctico.","detail":{"risks":"La forma potásica del lactato, común en productos cárnicos bajos en sodio. Se metaboliza igual que el lactato que produce tu propio cuerpo.","benefits":"","interestingFact":"","research":""}},"e327":{"name":"Lactato cálcico","note":"Sal del ácido láctico, también una fuente de calcio.","detail":{"risks":"Ácido láctico unido al calcio: utilizado para dar firmeza a las verduras en conserva e incluso para fortificar alimentos con calcio. Es el cristal crujiente que a veces se ve en el queso cheddar curado.","benefits":"","interestingFact":"","research":""}},"e330":{"name":"Ácido cítrico","note":"Ácido natural omnipresente.","detail":{"risks":"El ácido de los limones, producido industrialmente fermentando azúcar con un hongo (un proceso descubierto en 1917). Cada célula de tu cuerpo produce y quema ácido cítrico continuamente; el \\"ciclo del ácido cítrico\\" es la forma en que generas energía. El persistente rumor de que el \\"E330 causa cáncer\\" se remonta a un folleto de un bulo de los años 1970, una de las piezas de desinformación alimentaria más antiguas.","benefits":"","interestingFact":"","research":""}},"e331":{"name":"Citratos sódicos","note":"Sal del ácido cítrico.","detail":{"risks":"La sal del ácido cítrico: es lo que hace que el queso fundido se derrita suavemente en lugar de cortarse, al aflojar el calcio que mantiene unidas las proteínas de caseína.","benefits":"","interestingFact":"","research":""}},"e332":{"name":"Citratos potásicos","note":"Sal del ácido cítrico.","detail":{"risks":"Citrato que contiene potasio en lugar de sodio; un tampón de acidez que se metaboliza en el mismo ciclo energético que el propio ácido cítrico.","benefits":"","interestingFact":"","research":""}},"e333":{"name":"Citratos cálcicos","note":"Sal del ácido cítrico, también una fuente de calcio.","detail":{"risks":"Citrato unido al calcio: regulador de la acidez, agente de firmeza y la forma de calcio utilizada en muchos suplementos porque se absorbe bien.","benefits":"","interestingFact":"","research":""}},"e334":{"name":"Ácido tartárico","note":"Ácido natural de la uva.","detail":{"risks":"El ácido de las uvas y del vino; los cristales que a veces se encuentran en una botella de vino son su sal potásica. El ácido clásico de la levadura química.","benefits":"","interestingFact":"","research":""}},"e335":{"name":"Tartratos sódicos","note":"Sal del ácido de la uva.","detail":{"risks":"Ácido de la uva unido al sodio, un regulador de la acidez presente principalmente en mermeladas y jaleas. En gran medida no se absorbe.","benefits":"","interestingFact":"","research":""}},"e336":{"name":"Tartratos potásicos","note":"Cremor tártaro.","detail":{"risks":"Cremor tártaro, rascado, literalmente, del interior de los barriles de vino. El compañero tradicional del bicarbonato sódico en la levadura química y el estabilizador de las claras de huevo a punto de nieve.","benefits":"","interestingFact":"","research":""}},"e337":{"name":"Tartrato sódico potásico","note":"Sal de Rochelle, procedente de la vinificación.","detail":{"risks":"Sal de Rochelle, elaborada por primera vez por un boticario francés en 1675. Una celebridad de la cristalografía (fue el primer material que demostró ser piezoeléctrico) que realiza un trabajo discreto como regulador de la acidez.","benefits":"","interestingFact":"","research":""}},"e338":{"name":"Ácido fosfórico","note":"Ácido de los refrescos de cola; el consumo elevado de fosfato se asocia a problemas cardiovasculares.","detail":{"risks":"Lo que le da a los refrescos de cola su toque punzante (y su truco para eliminar el óxido). La preocupación no es la toxicidad aguda, sino la carga total de fosfato: la reevaluación de la EFSA de 2019 reveló que los consumidores elevados pueden superar la ingesta segura, y el exceso de fosfato se asocia a sobrecarga vascular y renal.","benefits":"","interestingFact":"","research":""}},"e339":{"name":"Fosfatos sódicos","note":"Consumo elevado de fosfato asociado a problemas cardiovasculares.","detail":{"risks":"Sales de fosfato de usos múltiples: retención de humedad, fundición, estabilización del pH. Seguras de forma individual, pero se acumulan: la revisión de la EFSA de 2019 advirtió que la ingesta total de fosfatos procedentes de alimentos procesados puede superar los niveles seguros.","benefits":"","interestingFact":"","research":""}},"e340":{"name":"Fosfatos potásicos","note":"Preocupación por la ingesta elevada de fosfato.","detail":{"risks":"La rama potásica de la familia de los fosfatos, común en bebidas deportivas y queso procesado. Misma precaución por carga acumulativa de fosfato que sus homólogos.","benefits":"","interestingFact":"","research":""}},"e341":{"name":"Fosfatos de calcio","note":"Fosfato; ingestas moderadas son aceptables.","detail":{"risks":"El mineral del que están hechos tus huesos y dientes, utilizado como gasificante y fortificante de calcio. El miembro más suave de la familia de los fosfatos: el calcio compensa en parte la preocupación por la carga de fosfato.","benefits":"","interestingFact":"","research":""}},"e343":{"name":"Fosfatos de magnesio","note":"Fosfato; ingestas moderadas son aceptables.","detail":{"risks":"Fosfato que aporta magnesio, utilizado como antiaglomerante y corrector de la acidez. Contribuye a la carga de fosfato, pero los niveles de uso habituales son ínfimos.","benefits":"","interestingFact":"","research":""}},"e350":{"name":"Malatos de sodio","note":"Sal del ácido málico.","detail":{"risks":"Ácido de manzana unido al sodio: un regulador de la acidez que se metaboliza igual que el ácido málico de cualquier manzana.","benefits":"","interestingFact":"","research":""}},"e351":{"name":"Malato de potasio","note":"Sal del ácido málico.","detail":{"risks":"La forma potásica del ácido de manzana, un corrector de la acidez poco utilizado y sin preocupaciones conocidas.","benefits":"","interestingFact":"","research":""}},"e352":{"name":"Malatos de calcio","note":"Sal del ácido málico.","detail":{"risks":"Ácido de manzana combinado con calcio; corrector de la acidez y agente de firmeza, se metaboliza como cualquier ácido frutal.","benefits":"","interestingFact":"","research":""}},"e353":{"name":"Ácido metatartárico","note":"Estabilizante del vino derivado del ácido de la uva.","detail":{"risks":"Moléculas de ácido de uva unidas en cadenas cortas; los enólogos lo añaden para evitar que se formen inofensivos cristales de tartrato en la botella. Con el tiempo vuelve a convertirse en ácido tartárico común.","benefits":"","interestingFact":"","research":""}},"e355":{"name":"Ácido adípico","note":"Ácido acidulante sintético para preparados en polvo.","detail":{"risks":"Un ácido acidulante que repele la humedad, lo que lo hace ideal para mezclas de bebidas en polvo y gelatinas. A nivel industrial es más conocido como precursor del nailon; su uso alimentario es un margen de error insignificante en su producción.","benefits":"","interestingFact":"","research":""}},"e363":{"name":"Ácido succínico","note":"Ácido de fermentación.","detail":{"risks":"Un ácido del mismo ciclo energético que el citrato: tus células lo producen constantemente. En los alimentos realza el sabor de postres en polvo; su nombre proviene del ámbar (succinum), de donde se destiló por primera vez.","benefits":"","interestingFact":"","research":""}},"e380":{"name":"Citrato triamónico","note":"Corrector de la acidez a base de citrato.","detail":{"risks":"Ácido cítrico neutralizado con amonio, utilizado para regular la acidez en quesos fundidos. El amonio se integra en el procesamiento normal de nitrógeno de tu cuerpo.","benefits":"","interestingFact":"","research":""}},"e385":{"name":"EDTA de calcio y disodio","note":"Quelante; preocupación por la absorción de minerales a dosis altas.","detail":{"risks":"Una pinza molecular que atrapa metales traza para que no catalicen el enranciamiento o la decoloración (mantiene claros los garbanzos en conserva). Esa misma capacidad de unión puede fijarse a los minerales de la dieta, de ahí los límites de dosis. También se usa médicamente para el envenenamiento por metales pesados.","benefits":"","interestingFact":"","research":""}},"e392":{"name":"Extracto de romero","note":"Antioxidante natural de hierbas.","detail":{"risks":"Antioxidantes concentrados (ácido carnósico) de las hojas de romero: el sustituto moderno de «etiqueta limpia» para el BHA/BHT.","benefits":"","interestingFact":"","research":""}},"e400":{"name":"Ácido algínico","note":"Espesante de algas pardas.","detail":{"risks":"La goma estructural del quelpo pardo: lo que mantiene flexibles a las algas bajo el agua. En tu intestino se comporta como fibra soluble.","benefits":"","interestingFact":"","research":""}},"e401":{"name":"Alginato de sodio","note":"Espesante de algas.","detail":{"risks":"Proviene del quelpo pardo; es famoso como el ingrediente de «esferificación» en gastronomía molecular que convierte líquidos en perlas similares al caviar. También es el gel de muchos remedios contra la acidez estomacal.","benefits":"","interestingFact":"","research":""}},"e402":{"name":"Alginato de potasio","note":"Espesante de algas.","detail":{"risks":"La forma potásica del alginato de quelpo; un espesante de fibra soluble sin preocupaciones conocidas.","benefits":"","interestingFact":"","research":""}},"e404":{"name":"Alginato de calcio","note":"Gelifante de algas.","detail":{"risks":"Alginato de quelpo cargado previamente con el calcio que lo hace gelificar; también se utiliza en apósitos para heridas por ese mismo truco de gelificación.","benefits":"","interestingFact":"","research":""}},"e405":{"name":"Alginato de propilenglicol","note":"Espesante de algas modificado (espuma de cerveza, aderezos).","detail":{"risks":"Alginato de quelpo modificado para resistir el ácido: es lo que mantiene la espuma de la cerveza firme y el aliño de ensalada espeso. La parte de propilenglicol se libera y se metaboliza sin causar daños.","benefits":"","interestingFact":"","research":""}},"e406":{"name":"Agar","note":"Gelifante de algas.","detail":{"risks":"Procedente de algas rojas: descubierto en Japón en 1658, es la gelatina estándar de los laboratorios de microbiología de todo el mundo. Cuaja más firme que la gelatina y se mantiene sólida a temperatura ambiente; es totalmente de origen vegetal.","benefits":"","interestingFact":"","research":""}},"e407":{"name":"Carragenanos","note":"Vínculo debatido con inflamación intestinal en su forma degradada.","detail":{"risks":"Extraído del musgo irlandés, se usa desde hace siglos en los pudines de leche irlandeses. El debate: el carragenano degradado (no la forma de uso alimentario) inflama el intestino de los animales, y si el ácido estomacal degrada la forma alimentaria sigue siendo motivo de controversia. La EFSA renovó su aprobación en 2018 pero solicitó más datos.","benefits":"","interestingFact":"","research":""}},"e407a":{"name":"Alga Eucheuma transformada","note":"Carragenano semirrefinado; mismo debate.","detail":{"risks":"Un carragenano menos purificado obtenido directamente del alga eucheuma de cultivo, que conserva algo de celulosa. Comparte el debate sobre la degradación del carragenano punto por punto.","benefits":"","interestingFact":"","research":""}},"e410":{"name":"Goma garrofín","note":"Espesante natural de garrofa.","detail":{"risks":"Semillas molidas del algarrobo. Dato curioso: el peso uniforme de las semillas de algarrobo nos dio el «quilate» de la joyería.","benefits":"","interestingFact":"","research":""}},"e412":{"name":"Goma guar","note":"Espesante natural.","detail":{"risks":"Habas de guar molidas procedentes de la India: ocho veces el poder espesante de la fécula de maíz. Es fibra soluble; cantidades muy grandes actúan como cualquier exceso de fibra.","benefits":"","interestingFact":"","research":""}},"e413":{"name":"Goma tragacanto","note":"Goma natural de savia de árbol.","detail":{"risks":"Savia seca de arbustos de astrágalo de Oriente Medio, cosechada desde la antigüedad; Teofrasto la describió en el 300 a. C. Es el endurecedor tradicional de las flores de azúcar en las tartas de boda.","benefits":"","interestingFact":"","research":""}},"e414":{"name":"Goma arábiga","note":"Goma arábiga natural.","detail":{"risks":"Savia del árbol de la acacia, cosechada como el jarabe de arce, principalmente en Sudán. Es lo que mantiene en suspensión los aceites cítricos en los refrescos y da su firmeza a las gominolas. Cuenta como fibra soluble.","benefits":"","interestingFact":"","research":""}},"e415":{"name":"Goma xantana","note":"Espesante derivado de fermentación.","detail":{"risks":"Producida mediante la fermentación de azúcar con bacterias Xanthomonas. Su superpoder es la «pseudoplasticidad»: espesa en reposo, líquida al agitarse; por eso el aliño de ensalada fluye pero no se separa. Un básico de la repostería sin gluten.","benefits":"","interestingFact":"","research":""}},"e416":{"name":"Goma karaya","note":"Goma de árbol; laxante suave a dosis altas.","detail":{"risks":"Savia del árbol indio Sterculia. En su mayor parte es fibra no digerible, razón por la cual grandes cantidades tienen un efecto laxante.","benefits":"","interestingFact":"","research":""}},"e417":{"name":"Goma tara","note":"Espesante natural de semillas.","detail":{"risks":"Semillas molidas del árbol peruano de la tara: una prima más suave de la goma guar y la goma garrofín, que se comporta como fibra soluble.","benefits":"","interestingFact":"","research":""}},"e418":{"name":"Goma gellan","note":"Gelifante derivado de fermentación.","detail":{"risks":"Producida por fermentación bacteriana como la xantana, pero gelifica en lugar de espesar: es lo que mantiene en suspensión la pulpa de algunos zumos y cuaja las gelatinas veganas con una textura sorprendentemente limpia.","benefits":"","interestingFact":"","research":""}},"e420":{"name":"Sorbitol","note":"Edulcorante poliol; laxante a dosis altas.","detail":{"risks":"Un poliol (alcohol de azúcar) presente de forma natural en las bayas del serbal y en las peras. Tiene la mitad de calorías que el azúcar y es respetuoso con los dientes, pero el sorbitol no absorbido fermenta en el colon: la razón por la cual los envases de chicle sin azúcar advierten sobre efectos laxantes.","benefits":"","interestingFact":"","research":""}},"e421":{"name":"Manitol","note":"Poliol; laxante a dosis altas.","detail":{"risks":"Un poliol cosechado originalmente del fresno del maná (de ahí su nombre bíblico). Casi no se absorbe, por lo que se aplica la precaución digestiva habitual de los polioles; su fusión refrescante aporta el toque fresco a caramelos de menta.","benefits":"","interestingFact":"","research":""}},"e422":{"name":"Glicerol","note":"Humectante que mantiene los alimentos húmedos.","detail":{"risks":"La molécula estructural de todas las grasas, liberada cada vez que se digiere grasa. En los alimentos retiene la humedad: es la razón por la que las barritas de proteínas se mantienen tiernas durante meses.","benefits":"","interestingFact":"","research":""}},"e425":{"name":"Konjac","note":"Restringido en golosinas de gelatina (riesgo de asfixia).","detail":{"risks":"Harina de raíz que sirve de base a los fideos shirataki japoneses. Su gel es tan firme y estable al calor que la EU lo prohibió en mini cápsulas de gelatina tras casos de asfixia mortales; como espesante alimentario en formatos normales es seguro.","benefits":"","interestingFact":"","research":""}},"e426":{"name":"Hemicelulosa de soja","note":"Emulsionante de fibra de soja.","detail":{"risks":"Fibra soluble extraída de la pulpa de soja, que evita que las bebidas lácteas ácidas se corten. Los consumidores alérgicos a la soja deben tener en cuenta su origen.","benefits":"","interestingFact":"","research":""}},"e432":{"name":"Polisorbato 20","note":"Emulsionante sintético; estudios sobre la microbiota en debate.","detail":{"risks":"El más pequeño de los emulsionantes-detergentes de la familia de los polisorbatos. La familia quedó bajo la lupa tras estudios en ratones en 2015 que mostraron un afinamiento de la capa de mucosidad intestinal; su relevancia en humanos aún se está evaluando.","benefits":"","interestingFact":"","research":""}},"e433":{"name":"Polisorbato 80","note":"Emulsionante sintético; estudios sobre la microbiota en debate.","detail":{"risks":"Un emulsionante de tipo detergente (helados, salsas). Un estudio de Nature de 2015 ampliamente citado descubrió que afinaba la capa protectora de mucosidad intestinal en ratones, promoviendo la inflamación; su relevancia en humanos aún se está evaluando, pero puso a los emulsionantes en el radar de los investigadores.","benefits":"","interestingFact":"","research":""}},"e434":{"name":"Polisorbato 40","note":"Emulsionante sintético; estudios sobre la microbiota en debate.","detail":{"risks":"Un emulsionante polisorbato de cadena media. Comparte el debate sobre la microbiota planteado por el estudio en ratones de Nature de 2015.","benefits":"","interestingFact":"","research":""}},"e435":{"name":"Polisorbato 60","note":"Emulsionante sintético; estudios sobre el microbioma en debate.","detail":{"risks":"Es el polisorbato más utilizado en cremas de pastelería y coberturas montadas: evita que las gotas de grasa se unan. Al igual que sus «hermanos», está envuelto en la investigación sobre la microbiota intestinal desencadenada por el estudio de Nature de 2015.","benefits":"","interestingFact":"","research":""}},"e436":{"name":"Polisorbato 65","note":"Emulsionante sintético; estudios sobre el microbioma en debate.","detail":{"risks":"El polisorbato más pesado, presente sobre todo en helados. Misma familia y las mismas preguntas abiertas sobre la microbiota.","benefits":"","interestingFact":"","research":""}},"e440":{"name":"Pectina","note":"Gelificante natural de frutas.","detail":{"risks":"El gel natural de la manzana y de la piel de los cítricos: lo que hace que la mermelada cuaje. Es fibra soluble y la razón por la que las abuelas añadían rodajas de manzana a las mermeladas demasiado líquidas.","benefits":"","interestingFact":"","research":""}},"e441":{"name":"Gelatina","note":"Gelificante de origen animal.","detail":{"risks":"Colágeno procedente de la piel y los huesos de animales, fragmentado en una proteína que se funde exactamente a la temperatura de la boca: la sensación de que los ositos de goma «se derriten en la boca» es una propiedad física del material, no un aroma.","benefits":"","interestingFact":"","research":""}},"e442":{"name":"Fosfátidos de amonio","note":"Emulsionante para chocolate, alternativa a la lecitina.","detail":{"risks":"Un primo sintético de la lecitina elaborado a partir de aceite de colza que cumple la misma función en el chocolate: permitir que fluya con menos manteca de cacao. Se digiere como la grasa común, más una traza de fosfato.","benefits":"","interestingFact":"","research":""}},"e444":{"name":"Acetoisobutirato de sacarosa","note":"Estabilizante de turbidez para bebidas cítricas.","detail":{"risks":"Una molécula densa derivada del azúcar que mantiene los aceites aromáticos cítricos en una turbidez uniforme dentro de los refrescos, evitando que formen un anillo en el cuello de la botella.","benefits":"","interestingFact":"","research":""}},"e445":{"name":"Ésteres glicéridos de la colofonia de la madera","note":"Mantiene mezclados los aceites cítricos en bebidas.","detail":{"risks":"Resina de pino purificada (el mismo material base con el que los violinistas frotan sus arcos) esterificada para mantener los aceites de aroma cítrico en suspensión en las bebidas deportivas.","benefits":"","interestingFact":"","research":""}},"e450":{"name":"Difosfatos","note":"Aditivo a base de fosfatos; debate cardiovascular con ingestas elevadas.","detail":{"risks":"El agente leudante de la levadura en polvo y el retenedor de agua en carnes procesadas y quesos. Seguro de forma individual, pero la revisión de la EFSA de 2019 advirtió que la ingesta total de fosfato procedente de todos los aditivos puede superar los niveles seguros en grandes consumidores: los fosfatos son la «sal oculta» de los alimentos ultraprocesados.","benefits":"","interestingFact":"","research":""}},"e451":{"name":"Trifosfatos","note":"Preocupación sobre aditivos a base de fosfatos.","detail":{"risks":"Cadenas de tres unidades de fosfato que hacen que la carne y el pescado en salmuera retengan agua (y peso). Se suman a la carga acumulativa de fosfato señalada por la EFSA en 2019.","benefits":"","interestingFact":"","research":""}},"e452":{"name":"Polifosfatos","note":"Preocupación sobre aditivos a base de fosfatos.","detail":{"risks":"Cadenas largas de fosfatos: los retenedores de agua más potentes de la familia, comunes en el glaseado del marisco congelado y en quesos fundidos. Misma precaución por ingesta acumulada que con los demás fosfatos.","benefits":"","interestingFact":"","research":""}},"e459":{"name":"Beta-ciclodextrina","note":"Soporte de aromas derivado del almidón.","detail":{"risks":"Un anillo de unidades de glucosa con un centro hueco que atrapa las moléculas de aroma y las libera lentamente: un empaquetado molecular elaborado a partir de almidón.","benefits":"","interestingFact":"","research":""}},"e460":{"name":"Celulosa","note":"Fibra vegetal.","detail":{"risks":"Fibra vegetal purificada, generalmente de pulpa de madera: volumen indigerible que aporta cremosidad y evita que el queso rallado se apelmace.","benefits":"","interestingFact":"","research":""}},"e461":{"name":"Metilcelulosa","note":"Fibra vegetal modificada; gelifica en caliente.","detail":{"risks":"Celulosa modificada químicamente con un truco de magia: gelifica cuando se calienta y se derrite cuando se enfría, justo al revés que la gelatina. Es lo que mantiene unidas las hamburguesas de origen vegetal en la parrilla.","benefits":"","interestingFact":"","research":""}},"e463":{"name":"Hidroxipropilcelulosa","note":"Fibra vegetal modificada.","detail":{"risks":"Celulosa modificada para aportar flexibilidad, usada principalmente como recubrimiento y aglutinante. Pasa por el tubo digestivo sin digerir, como cualquier fibra.","benefits":"","interestingFact":"","research":""}},"e464":{"name":"Hipromelosa","note":"Fibra vegetal modificada (también para cápsulas vegetarianas).","detail":{"risks":"La celulosa modificada con la que se fabrican las cápsulas medicinales vegetarianas; en los alimentos espesa y estabiliza. Indigerible y no absorbible.","benefits":"","interestingFact":"","research":""}},"e465":{"name":"Etilmetilcelulosa","note":"Fibra vegetal modificada.","detail":{"risks":"Una celulosa doblemente modificada que se utiliza para estabilizar espumas y emulsiones. Como el resto de la familia de las celulosas, se expulsa en forma de fibra.","benefits":"","interestingFact":"","research":""}},"e466":{"name":"Carboximetilcelulosa","note":"Emulsionante con efectos debatidos sobre el microbioma intestinal.","detail":{"risks":"Celulosa modificada utilizada en todo tipo de productos, desde helados hasta pasta de dientes. Protagonista junto con el polisorbato 80 en el estudio sobre la microbiota publicado en Nature en 2015; un ensayo pequeño en humanos de 2021 también mostró cambios en las bacterias intestinales, por lo que sigue siendo objeto de investigación activa.","benefits":"","interestingFact":"","research":""}},"e468":{"name":"CMC entrecruzada","note":"Celulosa modificada.","detail":{"risks":"Carboximetilcelulosa con sus cadenas entrelazadas para que se hinche en lugar de disolverse: principalmente un disgregante de comprimidos, ocasionalmente presente en alimentos. No se absorbe.","benefits":"","interestingFact":"","research":""}},"e470a":{"name":"Sales de los ácidos grasos","note":"Sales similares al jabón obtenidas de grasas comestibles.","detail":{"risks":"Moléculas de grasa comunes unidas a sodio, potasio o calcio: técnicamente jabón, en la práctica un antiaglomerante y desmoldeante que se digiere como la grasa.","benefits":"","interestingFact":"","research":""}},"e470b":{"name":"Sales de magnesio de los ácidos grasos","note":"Sal grasa antiaglomerante.","detail":{"risks":"Estearato de magnesio, conocido por estar presente en casi cualquier pastilla: evita que los polvos se peguen a la maquinaria. Se digiere como grasa más un suspiro de magnesio.","benefits":"","interestingFact":"","research":""}},"e471":{"name":"Mono- y diglicéridos de ácidos grasos","note":"Emulsionante común; puede contener grasas trans.","detail":{"risks":"El emulsionante más utilizado del mundo: moléculas de grasa parciales que unen el aceite y el agua, manteniendo el pan tierno y la margarina suave. Químicamente idéntico a los productos normales de la digestión de las grasas; la advertencia es que la producción industrial puede dejar trazas de grasas trans, invisibles en el etiquetado.","benefits":"","interestingFact":"","research":""}},"e472a":{"name":"Ésteres acéticos de los monoglicéridos y diglicéridos de ácidos grasos","note":"Emulsionante para coberturas y batidos.","detail":{"risks":"Emulsionante E471 con ácido acético unido: utilizado en coberturas para pasteles y natas en aerosol. Se digiere en grasa común y vinagre.","benefits":"","interestingFact":"","research":""}},"e472b":{"name":"Ésteres lácticos de los monoglicéridos y diglicéridos de ácidos grasos","note":"Emulsionante para nata montada.","detail":{"risks":"E471 con ácido láctico unido, que estabiliza las coberturas montadas. Se descompone en productos normales de digestión de grasas más lactato.","benefits":"","interestingFact":"","research":""}},"e472c":{"name":"Ésteres cítricos de los monoglicéridos y diglicéridos de ácidos grasos","note":"Emulsionante, también antisalpicaduras en grasas.","detail":{"risks":"E471 con ácido cítrico unido; evita que la margarina salpique en la sartén. Se digiere en grasa y citrato, ambos metabolitos habituales.","benefits":"","interestingFact":"","research":""}},"e472e":{"name":"DATEM","note":"Emulsionante para panadería, generalmente bien tolerado.","detail":{"risks":"Ésteres mono- y diacetiltartáricos de los mono- y diglicéridos de ácidos grasos: el reforzador de gluten de la panadería industrial que da al pan de supermercado una miga uniforme y volumen.","benefits":"","interestingFact":"","research":""}},"e473":{"name":"Sucroésteres de ácidos grasos","note":"Emulsionante, aceptable en dosis típicas.","detail":{"risks":"Azúcar unido a ácidos grasos: un emulsionante lo bastante suave como para que compuestos similares se estudien como ingredientes para fórmulas infantiles. Vuelve a dividirse en azúcar y grasa durante la digestión.","benefits":"","interestingFact":"","research":""}},"e475":{"name":"Ésteres poliglicéricos de ácidos grasos","note":"Emulsionante para bizcochos.","detail":{"risks":"Cadenas de glicerol unidas a ácidos grasos que incorporan aire en los bizcochos industriales para reducir la cantidad de huevo necesaria. Se digiere como la grasa.","benefits":"","interestingFact":"","research":""}},"e476":{"name":"Polirricinoleato de poliglicerol","note":"Emulsionante para chocolate (PGPR); aceptable según la EFSA en dosis típicas.","detail":{"risks":"Elaborado a partir de aceite de ricino, el PGPR mejora la fluidez del chocolate fundido para que los fabricantes usen menos cantidad de la costosa manteca de cacao. Su presencia es un indicador de coste, no de riesgo para la salud: la EFSA lo considera seguro a dosis muy superiores a la ingesta real.","benefits":"","interestingFact":"","research":""}},"e477":{"name":"Ésteres de propilenglicol de ácidos grasos","note":"Emulsionante para coberturas montadas.","detail":{"risks":"Ácidos grasos sobre una base de propilenglicol que airean las coberturas montadas y los preparados para bizcochos. Ambas partes son metabolitos habituales en dosis alimentarias.","benefits":"","interestingFact":"","research":""}},"e479b":{"name":"Ésteres de aceite de soja oxidado térmicamente","note":"Emulsionante antisalpicaduras para grasas de fritura.","detail":{"risks":"Aceite de soja tratado térmicamente y esterificado de forma deliberada para que la margarina para freír se dore de manera uniforme en lugar de salpicar. Revisado por la EFSA con un margen cómodo en los usos habituales.","benefits":"","interestingFact":"","research":""}},"e481":{"name":"Estearoil-2-lactilato sódico","note":"Emulsionante para panadería.","detail":{"risks":"Un híbrido de ácido esteárico y ácido láctico que refuerza la película de gluten: la razón por la que el pan de molde recupera su forma al apretarlo. Se digiere en grasa común y lactato.","benefits":"","interestingFact":"","research":""}},"e482":{"name":"Estearoil-2-lactilato cálcico","note":"Emulsionante para panadería.","detail":{"risks":"El gemelo de calcio del E481, que realiza la misma función de refuerzo de la masa en panes y preparados para tortitas.","benefits":"","interestingFact":"","research":""}},"e491":{"name":"Monoestearato de sorbitán","note":"Emulsionante, aceptable en dosis típicas.","detail":{"risks":"Sorbitol (un alcohol de azúcar) unido a grasa esteárica, apodado «cera sintética». Ayuda a que la levadura seca se rehidrate uniformemente y mantiene estables las coberturas montadas; la EFSA reconfirmó un margen de seguridad cómodo en 2017.","benefits":"","interestingFact":"","research":""}},"e492":{"name":"Triestearato de sorbitán","note":"Inhibidor del blanqueamiento del chocolate.","detail":{"risks":"Un emulsionante de sorbitán que frena el blanqueamiento grisáceo del chocolate: esos cristales de manteca de cacao que migran a la superficie con el tiempo. Misma familia y revisión de seguridad que el E491.","benefits":"","interestingFact":"","research":""}},"e493":{"name":"Monolaurato de sorbitán","note":"Emulsionante.","detail":{"risks":"El miembro con ácido láurico de la familia del sorbitán, utilizado en coberturas y glaseados. Se divide en sorbitol y grasa durante la digestión.","benefits":"","interestingFact":"","research":""}},"e495":{"name":"Monopalmitato de sorbitán","note":"Emulgente.","detail":{"risks":"El sorbitán de ácido palmítico, utilizado principalmente como coadyuvante de batido. La misma historia de digestión que sus hermanos E49x.","benefits":"","interestingFact":"","research":""}},"e500":{"name":"Carbonatos de sodio","note":"Bicarbonato de sodio.","detail":{"risks":"El bicarbonato de sodio y sus parientes: la fuente de gas en la mayoría de las levaduras químicas. También es lo que da a los pretzels y fideos ramen su característica textura masticable y alcalina.","benefits":"","interestingFact":"","research":""}},"e501":{"name":"Carbonatos de potasio","note":"Gasificante.","detail":{"risks":"El pariente potásico del bicarbonato de sodio; históricamente \\"ceniza de perla\\", lixiviada de cenizas de madera, el leudante del pan de jengibre anterior a las levaduras químicas.","benefits":"","interestingFact":"","research":""}},"e503":{"name":"Carbonatos de amonio","note":"Gasificante tradicional.","detail":{"risks":"\\"Amoníaco de panadería\\", el leudante anterior a la levadura química en las antiguas recetas europeas de galletas. Huele fuertemente a amoníaco en el horno, pero hasta la última traza se hornea, dejando galletas muy crujientes.","benefits":"","interestingFact":"","research":""}},"e504":{"name":"Carbonatos de magnesio","note":"Antiaglomerante (también tiza de escalada).","detail":{"risks":"El polvo blanco con el que los gimnastas y escaladores se impregnan las manos, que mantiene la sal de mesa fluida. El ácido del estómago lo transforma en simple magnesio disuelto.","benefits":"","interestingFact":"","research":""}},"e507":{"name":"Ácido clorhídrico","note":"Ácido de procesado, neutralizado en el producto.","detail":{"risks":"Suena alarmante, pero su estómago produce el mismo ácido a mayor concentración todos los días. En el procesamiento de alimentos se neutraliza antes de terminar el producto.","benefits":"","interestingFact":"","research":""}},"e508":{"name":"Cloruro de potasio","note":"Mineral sustituto de la sal.","detail":{"risks":"El sustituto estándar de la sal bajo en sodio: potasio en lugar de sodio, con un toque ligeramente metálico. Para la mayoría de la gente, el potasio extra es una ventaja.","benefits":"","interestingFact":"","research":""}},"e509":{"name":"Cloruro de calcio","note":"Endurecedor (conservas vegetales, elaboración de queso).","detail":{"risks":"Una sal de calcio que entrecruza las pectinas vegetales, manteniendo firmes los tomates y pepinillos en conserva. Los queseros lo añaden a la leche para ayudar a cuajar la masa. También es el \\"líquido\\" de muchos anticongelantes; la concentración lo es todo.","benefits":"","interestingFact":"","research":""}},"e511":{"name":"Cloruro de magnesio","note":"Endurecedor (también coagulante del tofu, nigari).","detail":{"risks":"Magnesio del agua de mar: como \\"nigari\\", el coagulante tradicional del tofu japonés que cuaja la leche de soja. Una fuente de magnesio en la dieta.","benefits":"","interestingFact":"","research":""}},"e513":{"name":"Ácido sulfúrico","note":"Ácido de procesado, neutralizado en el producto.","detail":{"risks":"Utilizado solo durante el procesado (para ajustar la acidez en el agua de elaboración de cerveza, por ejemplo) y neutralizado por completo en sales de sulfato antes de llegar a las estanterías.","benefits":"","interestingFact":"","research":""}},"e514":{"name":"Sulfatos de sodio","note":"Corrector de la acidez.","detail":{"risks":"Una sal mineral neutra: la sal de Glauber para los boticarios del siglo XVIII, que la recetaban como laxante, algo que sigue siendo en grandes cantidades.","benefits":"","interestingFact":"","research":""}},"e516":{"name":"Sulfato de calcio","note":"Yeso: coagulante de tofu, tratamiento de la harina.","detail":{"risks":"Yeso de grado alimentario (el mineral del cartón yeso, purificado). Es el clásico coagulante del tofu chino y un nutriente para la levadura en panadería, aportando calcio aprovechable por el camino.","benefits":"","interestingFact":"","research":""}},"e524":{"name":"Hidróxido de sodio","note":"Sosa cáustica: agente de procesado, reaccionado totalmente en el producto.","detail":{"risks":"Cáustico en la botella, inofensivo en el plato: los pretzels obtienen su corteza de color caoba tras sumergirse en sosa, y se neutraliza por completo al hornear.","benefits":"","interestingFact":"","research":""}},"e526":{"name":"Hidróxido de calcio","note":"Cal de encurtir, coadyuvante de elaboración.","detail":{"risks":"Cal apagada: la \\"cal\\" de la nixtamalización mexicana, que ha ablandado el maíz para tortillas durante 3500 años y libera su niacina. Reacciona por completo en el alimento final.","benefits":"","interestingFact":"","research":""}},"e527":{"name":"Hidróxido de amonio","note":"Álcali de procesado.","detail":{"risks":"Solución de amoníaco utilizada para ajustar la acidez durante el procesado (especialmente del cacao). Reacciona o se evapora; el amonio restante se incorpora al metabolismo normal del nitrógeno.","benefits":"","interestingFact":"","research":""}},"e529":{"name":"Óxido de calcio","note":"Cal viva, coadyuvante de elaboración.","detail":{"risks":"Cal viva: se apaga convirtiéndose en hidróxido de calcio en cuanto entra en contacto con la humedad, haciendo la misma función que el E526 y acabando como simple calcio.","benefits":"","interestingFact":"","research":""}},"e530":{"name":"Óxido de magnesio","note":"Mineral antiaglomerante.","detail":{"risks":"El mismo óxido de magnesio que se vende como suplemento y antiácido, utilizado aquí para mantener fluido el cacao en polvo.","benefits":"","interestingFact":"","research":""}},"e535":{"name":"Ferrocianuro de sodio","note":"Antiaglomerante en la sal.","detail":{"risks":"A pesar del nombre aterrador, el cianuro está tan fuertemente unido al hierro que pasa sin absorberse; es lo que mantiene la sal de mesa fluida en clima húmedo.","benefits":"","interestingFact":"","research":""}},"e536":{"name":"Ferrocianuro de potasio","note":"Antiaglomerante en la sal.","detail":{"risks":"La forma potásica del E535, con la misma química unida al hierro: el grupo cianuro no puede liberarse en el organismo, y la EFSA reconfirmó su seguridad en 2018.","benefits":"","interestingFact":"","research":""}},"e538":{"name":"Ferrocianuro de calcio","note":"Antiaglomerante en la sal.","detail":{"risks":"La más rara de las tres sales antiaglomerantes de ferrocianuro, con idéntica química bloqueada y la misma evaluación de la EFSA.","benefits":"","interestingFact":"","research":""}},"e541":{"name":"Fosfato sódico de aluminio","note":"Gasificante a base de aluminio.","detail":{"risks":"Un ácido de repostería de acción lenta cuyo aluminio contribuye a la exposición dietética total: la EFSA endureció las normas sobre aditivos de aluminio en 2012 y prácticamente ha desaparecido de las recetas de la EU.","benefits":"","interestingFact":"","research":""}},"e551":{"name":"Dióxido de silicio","note":"Antiaglomerante; contenido de nanopartículas bajo revisión en la EU.","detail":{"risks":"Arena purificada en forma de polvo tan fino que recubre las partículas y mantiene fluidas las mezclas de especias y sopas instantáneas. Químicamente inerte; la cuestión pendiente que investiga la EFSA es si su fracción de tamaño nanométrico puede acumularse.","benefits":"","interestingFact":"","research":""}},"e552":{"name":"Silicato de calcio","note":"Mineral antiaglomerante.","detail":{"risks":"Un mineral de tiza y sílice que absorbe humedad varias veces su peso, manteniendo los polvos sueltos. Esencialmente no se absorbe.","benefits":"","interestingFact":"","research":""}},"e553b":{"name":"Talco","note":"Mineral antiaglomerante (grado alimentario, sin amianto).","detail":{"risks":"El mineral más blando de la Tierra, utilizado para pulir granos de arroz y espolvorear chicles. El de grado alimentario está certificado como libre de amianto y pasa por el aparato digestivo sin digerirse.","benefits":"","interestingFact":"","research":""}},"e554":{"name":"Silicato de aluminio y sodio","note":"Antiaglomerante a base de aluminio.","detail":{"risks":"Una arcilla antiaglomerante cuyo contenido de aluminio cuenta para el estricto límite semanal de aluminio de la EFSA, razón por la cual los reguladores de la EU redujeron este grupo en 2014.","benefits":"","interestingFact":"","research":""}},"e555":{"name":"Silicato de aluminio y potasio","note":"Soporte a base de aluminio (colores perlados).","detail":{"risks":"Mica natural: el brillo bajo las decoraciones perladas de tartas. Señalado por la misma razón de acumulación de aluminio que sus hermanos.","benefits":"","interestingFact":"","research":""}},"e558":{"name":"Bentonita","note":"Arcilla utilizada para clarificar vino y zumo.","detail":{"risks":"Una arcilla volcánica que se hincha en agua y atrapa las proteínas que forman la turbidez; la mayor parte del vino blanco que ha bebido se clarificó con ella y luego se filtró.","benefits":"","interestingFact":"","research":""}},"e559":{"name":"Caolín","note":"Arcilla antiaglomerante.","detail":{"risks":"Arcilla de China (el mineral de la porcelana) utilizada ocasionalmente como antiaglomerante. Inerte y no absorbible.","benefits":"","interestingFact":"","research":""}},"e570":{"name":"Ácidos grasos","note":"Ácidos grasos comestibles comunes.","detail":{"risks":"El esteárico y sus parientes: los mismos ácidos grasos que su cuerpo obtiene de cualquier grasa, utilizados como agentes de recubrimiento y antiaglomerantes.","benefits":"","interestingFact":"","research":""}},"e575":{"name":"Glucono-delta-lactona","note":"Ácido de liberación lenta (tofu, carnes curadas).","detail":{"risks":"Un azúcar oxidado que se vuelve ácido lentamente en agua: perfecto para el tofu sedoso, donde la bajada gradual del pH cuaja la leche de soja en un gel suave.","benefits":"","interestingFact":"","research":""}},"e576":{"name":"Gluconato de sodio","note":"Sal mineral del ácido glucónico.","detail":{"risks":"Glucosa oxidada y unida al sodio: un portador mineral y estabilizante que se metaboliza como el azúcar.","benefits":"","interestingFact":"","research":""}},"e577":{"name":"Gluconato de potasio","note":"Sal mineral del ácido glucónico.","detail":{"risks":"La forma potásica del gluconato, lo suficientemente suave como para que las farmacias la vendan como suplemento de potasio.","benefits":"","interestingFact":"","research":""}},"e578":{"name":"Gluconato de calcio","note":"Sal de calcio, endurecedor.","detail":{"risks":"Calcio en un soporte de ácido de azúcar: el mismo compuesto que los hospitales administran por vía intravenosa para el calcio bajo. En los alimentos reafirma frutas y verduras.","benefits":"","interestingFact":"","research":""}},"e579":{"name":"Gluconato ferroso","note":"Sal de hierro: oscurece las aceitunas.","detail":{"risks":"Un suplemento de hierro que cumple una función de color: las aceitunas \\"negras\\" en lata suelen ser aceitunas verdes oxidadas a negro y fijadas con esta sal de hierro.","benefits":"","interestingFact":"","research":""}},"e585":{"name":"Lactato ferroso","note":"Sal de hierro, oscurecedor de aceitunas.","detail":{"risks":"Hierro transportado por lactato, que realiza el mismo trabajo de oscurecimiento de aceitunas que el E579 y se utiliza para fortificar alimentos con hierro.","benefits":"","interestingFact":"","research":""}},"e586":{"name":"4-Hexilresorcinol","note":"Agente antipardeamiento para camarones y langostinos.","detail":{"risks":"Evita que el caparazón de los langostinos desarrolle manchas negras tras la captura al bloquear la misma enzima que parda las manzanas cortadas. También es un antiséptico para las pastillas de la garganta.","benefits":"","interestingFact":"","research":""}},"e620":{"name":"Ácido glutámico","note":"Potenciador del umami; reacciones de sensibilidad en algunas personas.","detail":{"risks":"La forma libre del aminoácido más abundante en tu dieta: el parmesano es un 1,2% glutamato puro. Como aditivo concentra el umami; los debates sobre la sensibilidad y el comer en exceso reflejan los del GMS (E621).","benefits":"","interestingFact":"","research":""}},"e621":{"name":"Glutamato monosódico","note":"Potenciador del sabor; reacciones de sensibilidad en algunas personas.","detail":{"risks":"La forma pura del umami, identificada en 1908 a partir del caldo de alga kombu. El glutamato en sí está presente en el parmesano, los tomates y la leche materna; la psicosis del «síndrome del restaurante chino» de 1968 fracasó en gran medida en los ensayos controlados, aunque una minoría sí reacciona a dosis altas. La EFSA fijó un límite de ingesta formal en 2017, superado principalmente por dietas ricas en aperitivos procesados. Su verdadero problema nutricional: hace que la comida ultraprocesada sea muy fácil de comer en exceso.","benefits":"","interestingFact":"","research":""}},"e622":{"name":"Glutamato monopotásico","note":"Potenciador del sabor a base de glutamato.","detail":{"risks":"GMS con potasio en lugar de sodio, utilizado en recetas bajas en sodio. Mecanismo de umami idéntico y el mismo límite de ingesta de glutamato de la EFSA.","benefits":"","interestingFact":"","research":""}},"e627":{"name":"Guanilato disódico","note":"Potenciador del sabor, a menudo combinado con GMS.","detail":{"risks":"Un nucleótido que multiplica el umami: combinado con GMS, sabe hasta 30× más intenso que cualquiera de los dos por separado, razón por la cual suelen ir juntos en las etiquetas. Se obtiene de levadura o pescado; se aconseja a las personas con gota que limiten los aditivos ricos en purinas como este.","benefits":"","interestingFact":"","research":""}},"e628":{"name":"Guanilato dipotásico","note":"Potenciador del sabor nucleotídico.","detail":{"risks":"La forma potásica del guanilato (E627), que amplifica el umami en productos bajos en sodio. Mismo origen en levadura y misma advertencia sobre purinas para personas con tendencia a la gota.","benefits":"","interestingFact":"","research":""}},"e631":{"name":"Inosinato disódico","note":"Potenciador del sabor, a menudo combinado con GMS.","detail":{"risks":"El nucleótido umami de las escamas de bonito seco (la base del dashi japonés), hoy producido por fermentación. Misma sinergia con el GMS y misma advertencia sobre purinas que el E627.","benefits":"","interestingFact":"","research":""}},"e635":{"name":"5'-Ribonucleótidos de disodio","note":"Combinación de E627 + E631; potenciador del umami.","detail":{"risks":"Una mezcla al 50/50 de guanilato e inosinato: una sola línea en la etiqueta que aporta ambos nucleótidos umami. Su presencia casi siempre indica que hay GMS (o un extracto rico en glutamato) cerca, ya que hace muy poco por sí solo.","benefits":"","interestingFact":"","research":""}},"e640":{"name":"Glicina","note":"El aminoácido más simple, con un dulzor suave.","detail":{"risks":"El aminoácido más pequeño: un tercio de la proteína del colágeno es glicina. Como aditivo, suaviza los matices amargos y aporta un ligero toque dulce.","benefits":"","interestingFact":"","research":""}},"e650":{"name":"Acetato de zinc","note":"Sal de zinc (chicle).","detail":{"risks":"Zinc unido a ácido acético, usado principalmente en chicles para refrescar el aliento, donde el zinc neutraliza los compuestos de azufre. La misma sal se utiliza en pastillas para el resfriado.","benefits":"","interestingFact":"","research":""}},"e900":{"name":"Dimetilpolisiloxano","note":"Agente antiespumante de silicona (aceite de freír).","detail":{"risks":"Una silicona de grado alimentario que evita que el aceite de freír haga espuma y se desborde: la razón por la que las freidoras de comida rápida no rebosan. Completamente inerte y no se absorbe; también es el ingrediente principal del Silly Putty.","benefits":"","interestingFact":"","research":""}},"e901":{"name":"Cera de abejas","note":"Cera de recubrimiento natural.","detail":{"risks":"La misma cera con la que las abejas construyen los panales, aplicada en golosinas y cítricos para darles brillo. Indigestible: pasa directamente a través del organismo.","benefits":"","interestingFact":"","research":""}},"e902":{"name":"Cera de candelilla","note":"Cera vegetal de recubrimiento.","detail":{"risks":"Cera rascada de un arbusto del desierto mexicano que se recubre a sí mismo para protegerse de la sequía, y que ahora recubre tus ositos de goma. Indigestible e inerte.","benefits":"","interestingFact":"","research":""}},"e903":{"name":"Cera de carnauba","note":"Cera de recubrimiento de hoja de palmera.","detail":{"risks":"Procedente de las hojas de la palmera brasileña: la cera natural más dura que se conoce, capaz de dar brillo tanto a los M&M's como a los coches deportivos.","benefits":"","interestingFact":"","research":""}},"e904":{"name":"Goma laca","note":"Recubrimiento de resina de insecto.","detail":{"risks":"Secretada por el gusano de la laca en árboles de Tailandia y la India, y luego purificada: es la capa brillante sobre las grageas de chocolate y las manzanas, y la misma resina utilizada en el barnizado a muñequilla de muebles. No es apta para vegetarianos.","benefits":"","interestingFact":"","research":""}},"e905":{"name":"Cera microcristalina","note":"Cera de recubrimiento derivada del petróleo.","detail":{"risks":"Una cera de petróleo altamente refinada que recubre chicles y caramelos. Demasiado grande para ser absorbida, pasa de largo: la única exigencia de la EFSA es el control de su pureza.","benefits":"","interestingFact":"","research":""}},"e914":{"name":"Cera de polietileno oxidada","note":"Cera sintética para recubrimiento de cítricos.","detail":{"risks":"Una cera sintética pulverizada sobre la piel de los cítricos para frenar la pérdida de humedad desde el huerto hasta el estante. Permanece en la piel; lava la fruta antes de rallarla.","benefits":"","interestingFact":"","research":""}},"e920":{"name":"L-Cisteína","note":"Acondicionador de masa procedente de fermentación.","detail":{"risks":"Un aminoácido que relaja el gluten para que las máquinas industriales de masa puedan estirarlo rápidamente. Históricamente extraído de plumas y cabello humano (fuentes prohibidas en la EU desde 2001; ahora se fermenta a partir de azúcar), un dato que mantiene viva su colorida reputación.","benefits":"","interestingFact":"","research":""}},"e927b":{"name":"Carbamida","note":"Texturizante para chicles.","detail":{"risks":"Urea —una molécula que tu cuerpo produce constantemente en el metabolismo de las proteínas— que ablanda el chicle sin azúcar. Irrelevante a las dosis de miligramos de las que se trata.","benefits":"","interestingFact":"","research":""}},"e938":{"name":"Argón","note":"Gas de envasado inerte.","detail":{"risks":"Un gas noble del aire (el 1% de cada bocanada) que no reacciona con nada: se inyecta en los envases para expulsar el oxígeno.","benefits":"","interestingFact":"","research":""}},"e939":{"name":"Helio","note":"Gas de envasado inerte.","detail":{"risks":"El gas de los globos, completamente inerte, utilizado ocasionalmente para envolver los alimentos en el envasado. Se escapa en cuanto abres el paquete.","benefits":"","interestingFact":"","research":""}},"e941":{"name":"Nitrógeno","note":"Gas de envasado: el 78% del aire que respiras.","detail":{"risks":"El gas que llena el espacio «vacío» de las bolsas de patatas no es un engaño: es nitrógeno que protege las patatas del oxígeno y del aplastamiento. También es lo que hace que el café nitro sea cremoso.","benefits":"","interestingFact":"","research":""}},"e942":{"name":"Óxido nitroso","note":"Propulsor de montado (gas de la risa).","detail":{"risks":"El propulsor de las cargas de nata montada. Se disuelve en la nata a presión y se expande ocho veces al liberarse: el rastro que ingieres desaparece en cuestión de minutos.","benefits":"","interestingFact":"","research":""}},"e948":{"name":"Oxígeno","note":"Gas de envasado.","detail":{"risks":"Oxígeno puro, a veces añadido a los envases de carne roja para mantener la superficie de un rojo brillante. Inhalas mucho más en cada respiración.","benefits":"","interestingFact":"","research":""}},"e949":{"name":"Hidrógeno","note":"Gas de envasado.","detail":{"risks":"El gas más ligero, raramente utilizado como atmósfera de envasado. Inerte en la comida y desaparece mucho antes de que te lo comas.","benefits":"","interestingFact":"","research":""}},"e999":{"name":"Extracto de quillay","note":"Agente espumante de corteza de jabón (espuma de la cerveza de raíz).","detail":{"risks":"Extracto del árbol chileno de la corteza de jabón, cuyas saponinas naturales forman la corona de espuma de la cerveza de raíz. El mismo extracto se utiliza como adyuvante de vacunas; a dosis alimentarias solo forma burbujas.","benefits":"","interestingFact":"","research":""}},"e950":{"name":"Acesulfamo K","note":"Edulcorante artificial; efectos a largo plazo en debate.","detail":{"risks":"200× más dulce que el azúcar, cero calorías, no se metaboliza en absoluto: abandona tu cuerpo sin cambios en 24 horas. La epidemiología a largo plazo (incluida la recomendación de la WHO en 2023 contra los edulcorantes para el control de peso) mantiene el debate abierto.","benefits":"","interestingFact":"","research":""}},"e951":{"name":"Aspartamo","note":"IARC clase 2B (posiblemente carcinógeno, 2023); se aplican límites de ingesta.","detail":{"risks":"Dos aminoácidos unidos, 200× más dulce que el azúcar. En 2023, la IARC lo clasificó como «posiblemente carcinógeno» (la misma categoría 2B que el aloe vera y las verduras en encurtido), mientras que el comité de aditivos alimentarios de la WHO mantuvo su límite de ingesta: unas 12 latas de refresco dietético al día para un adulto. Las personas con la enfermedad genética PKU deben evitarlo por completo; para eso sirve la advertencia «contiene una fuente de fenilalanina».","benefits":"","interestingFact":"","research":""}},"e952":{"name":"Ciclamatos","note":"Edulcorante prohibido en EE. UU., dosis restringidas en la EU.","detail":{"risks":"Descubierto en 1937 por un estudiante que apoyó su cigarrillo sobre un polvo del laboratorio y probó su dulzor. Prohibido en EE. UU. desde 1970 por hallazgos (posteriormente disputados) de tumores en ratas; la EU lo permite con límites estrictos.","benefits":"","interestingFact":"","research":""}},"e953":{"name":"Isomaltosa","note":"Poliol; laxante a dosis altas.","detail":{"risks":"El favorito de los escultores de azúcar: se derrite transparente como el cristal sin caramelizarse, por lo que las piezas exhibidas en los concursos de repostería de la televisión suelen ser de isomaltosa. Se aplican las precauciones digestivas habituales para los polioles.","benefits":"","interestingFact":"","research":""}},"e954":{"name":"Sacarina","note":"Edulcorante artificial con un historial debatido.","detail":{"risks":"El edulcorante artificial más antiguo (1879, descubierto por un químico que no se lavó las manos antes de cenar). Llevó una advertencia de cáncer en EE. UU. durante 20 años hasta que se demostró que el mecanismo de vejiga en ratas no se aplicaba a los humanos; retirado de la lista en 2000, pero su larga sombra perdura.","benefits":"","interestingFact":"","research":""}},"e955":{"name":"Sucralosa","note":"Edulcorante artificial; debates sobre su calentamiento y la microbiota.","detail":{"risks":"Azúcar con tres átomos de cloro intercambiados: 600× más dulce y en gran parte no absorbida. Debates actuales: puede descomponerse en compuestos cuestionables a altas temperaturas de horneado, y los estudios discrepan sobre sus efectos en la microbiota intestinal.","benefits":"","interestingFact":"","research":""}},"e957":{"name":"Taumatina","note":"Proteína dulce de una fruta africana.","detail":{"risks":"Una proteína del fruto del katemfe de África occidental: la sustancia natural más dulce que se conoce, unas 2 000× más dulce que el azúcar en peso. Se digiere como cualquier otra proteína.","benefits":"","interestingFact":"","research":""}},"e959":{"name":"Neohesperidina DC","note":"Edulcorante derivado de cítricos.","detail":{"risks":"Elaborado a partir de compuestos de la piel de naranja amarga, 1 500× más dulce que el azúcar con un posgusto que recuerda al mentol; también se utiliza para enmascarar el amargor en los medicamentos.","benefits":"","interestingFact":"","research":""}},"e960":{"name":"Glicósidos de esteviol","note":"Edulcorante derivado de la estevia.","detail":{"risks":"Extraído de las hojas de estevia, utilizado por el pueblo guaraní en Paraguay durante siglos. 250–300× más dulce que el azúcar con cero calorías; las bacterias intestinales lo descomponen y se excreta. El ligero posgusto a regaliz es el precio a pagar.","benefits":"","interestingFact":"","research":""}},"e961":{"name":"Neotamo","note":"Derivado del aspartamo, 8000× más dulce que el azúcar.","detail":{"risks":"Aspartamo rediseñado para ser ~40× más potente y estable al horneado. Las dosis son microscópicas y, a diferencia del aspartamo, libera tan poca fenilalanina que no requiere advertencia para la PKU; los datos a largo plazo son simplemente más escasos.","benefits":"","interestingFact":"","research":""}},"e962":{"name":"Sal de aspartamo y acesulfamo","note":"Edulcorante combinado; véanse las notas del aspartamo.","detail":{"risks":"El aspartamo y el acesulfamo K se cristalizan juntos en una sola molécula que vuelve a dividirse en ambos en la boca; se aplican todas las consideraciones de cada uno, incluida la advertencia sobre la PKU.","benefits":"","interestingFact":"","research":""}},"e965":{"name":"Maltitol","note":"Poliol; laxante a dosis altas.","detail":{"risks":"El sustituto del azúcar habitual en el chocolate «sin azúcares añadidos»: un 90% tan dulce como el azúcar con la mitad de calorías. También es el poliol más conocido por provocar molestias digestivas por encima de ~20 g, de ahí las advertencias en los caramelos sin azúcar.","benefits":"","interestingFact":"","research":""}},"e966":{"name":"Lactitol","note":"Poliol derivado de la leche; laxante a dosis altas.","detail":{"risks":"Un alcohol de azúcar elaborado a partir del azúcar de la leche, ligeramente dulce y fermentado en su mayor parte por las bacterias intestinales; a dosis farmacéuticas, la misma molécula se vende literalmente como laxante.","benefits":"","interestingFact":"","research":""}},"e967":{"name":"Xilitol","note":"Poliol; laxante a dosis altas.","detail":{"risks":"Alcohol de azúcar derivado de la corteza de abedul que las bacterias bucales no pueden fermentar: masticar chicle con xilitol reduce de forma medible las caries, siendo el raro aditivo con un beneficio demostrado. Dos advertencias: es laxante por encima de ~30 g y extremadamente tóxico para los perros.","benefits":"","interestingFact":"","research":""}},"e968":{"name":"Eritritol","note":"Poliol; un estudio de 2023 abrió un debate cardiovascular.","detail":{"risks":"El poliol más suave: el 90% se absorbe antes de llegar al colon, por lo que casi no tiene efecto digestivo y aporta cero calorías. Un estudio de 2023 en Nature Medicine asoció niveles elevados de eritritol en sangre con riesgo de coagulación; si el eritritol de la dieta promueve esto es algo que se está investigando activamente.","benefits":"","interestingFact":"","research":""}},"e1103":{"name":"Invertasa","note":"Enzima que liquida el centro de los caramelos.","detail":{"risks":"La enzima (obtenida de la levadura) que transforma el fondant firme en líquido a lo largo de semanas: así es como las cerezas cubiertas de chocolate consiguen su centro líquido tras ser rellenadas con pasta sólida.","benefits":"","interestingFact":"","research":""}},"e1105":{"name":"Lisozima","note":"Enzima conservante de la clara de huevo (queso, vino).","detail":{"risks":"Una enzima antibacteriana de la clara de huevo: la misma que se encuentra en tus lágrimas y saliva. Los consumidores con alergia al huevo deben saber que se esconde en algunos quesos curados y vinos.","benefits":"","interestingFact":"","research":""}},"e1200":{"name":"Polidextrosa","note":"Fibra soluble sintética.","detail":{"risks":"Glucosa enlazada con patrones que tus enzimas no pueden cortar, por lo que se comporta como fibra soluble: añade volumen a los alimentos «light» a 1 kcal/g en lugar de las 4 kcal/g del azúcar.","benefits":"","interestingFact":"","research":""}},"e1201":{"name":"Polivinilpirrolidona","note":"Clarificante y aglutinante de comprimidos.","detail":{"risks":"Un polímero que atrapa los polifenoles que enturbiarían la cerveza y el zumo, y luego se filtra junto con ellos. Cualquier traza que permanezca pasa sin ser absorbida.","benefits":"","interestingFact":"","research":""}},"e1400":{"name":"Dextrinas","note":"Espesante de almidón tostado.","detail":{"risks":"Almidón ligeramente descompuesto por tostado, la misma química que dora la corteza de una baguette. Se digiere exactamente igual que el almidón.","benefits":"","interestingFact":"","research":""}},"e1404":{"name":"Almidón oxidado","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Almidón tratado para espesar a menor viscosidad en cremas y masas. «Modificado» significa ajustado física o químicamente —no modificado genéticamente— y se digiere como almidón ordinario.","benefits":"","interestingFact":"","research":""}},"e1410":{"name":"Fosfato de monoalmidón","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Almidón con anclajes de fosfato que resisten el calor y el ácido, manteniendo espesas las salsas en conserva. Se digiere como el almidón.","benefits":"","interestingFact":"","research":""}},"e1412":{"name":"Fosfato de dialmidón","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Almidón entrecruzado con puentes de fosfato para resistir el agitado y el calor: la base de los pudines instantáneos. Se digiere como el almidón.","benefits":"","interestingFact":"","research":""}},"e1414":{"name":"Fosfato de dialmidón acetilado","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Almidón entrecruzado con grupos acetilo añadidos para dar estabilidad al congelado y descongelado, razón por la cual los platos preparados congelados no sueltan agua al recalentarse. Se digiere como el almidón.","benefits":"","interestingFact":"","research":""}},"e1420":{"name":"Almidón acetilado","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Almidón con grupos acetilo derivados del vinagre, que resiste la retrogradación (el proceso de endurecimiento). Se digiere como el almidón.","benefits":"","interestingFact":"","research":""}},"e1422":{"name":"Adipato de dialmidón acetilado","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"«Almidón modificado» no significa modificado genéticamente: es almidón de maíz o patata modificado químicamente para que las salsas resistan la congelación y el recalentamiento sin volverse acuosas. Tu cuerpo lo digiere como almidón ordinario.","benefits":"","interestingFact":"","research":""}},"e1440":{"name":"Hidroxipropilalmidón","note":"Almidón modificado, generalmente bien tolerado.","detail":{"risks":"Almidón al que se añaden grupos laterales afines al agua para lograr un espesamiento suave a bajas temperaturas. Se digiere en gran medida como almidón; la fracción modificada pasa como fibra.","benefits":"","interestingFact":"","research":""}},"e1442":{"name":"Fosfato de dialmidón hidroxipropilado","note":"Almidón modificado, generalmente bien tolerado.","detail":{"risks":"El más resistente de los almidones modificados: entrecruzado y sustituido, espesa a través del enlatado, la congelación y el recalentamiento por igual. Se digiere en su mayor parte como almidón.","benefits":"","interestingFact":"","research":""}},"e1450":{"name":"Octenilsuccinato sódico de almidón","note":"Emulsionante a base de almidón (también en vitaminas).","detail":{"risks":"Almidón provisto de una cola afín a las grasas para que pueda emulsionar: el vehículo que mantiene uniformemente dispersos los aromas en polvo y las vitaminas en fórmulas infantiles.","benefits":"","interestingFact":"","research":""}},"e1451":{"name":"Almidón oxidado acetilado","note":"Almidón modificado; se digiere como el almidón.","detail":{"risks":"Un almidón sometido a doble tratamiento que combina la claridad de la oxidación con la estabilidad del acetilo. Aun así, desde el punto de vista digestivo, es simplemente almidón.","benefits":"","interestingFact":"","research":""}},"e1505":{"name":"Citrato de trietilo","note":"Portador de aroma a base de citrato y estabilizador de espuma.","detail":{"risks":"Ácido cítrico con tres grupos etanol: estabiliza la clara de huevo montada en huevo líquido envasado y transporta aromas. Durante la digestión se vuelve a dividir en citrato y trazas de alcohol.","benefits":"","interestingFact":"","research":""}},"e1518":{"name":"Triacetina","note":"Portador de aromas a base de glicerol.","detail":{"risks":"Glicerol con tres grupos de ácido acético, que disuelve aromas en chicles y caramelos. Se digiere en glicerol y acetato, ambos metabolitos habituales.","benefits":"","interestingFact":"","research":""}},"e1520":{"name":"Propilenglicol","note":"Portador de aromas; seguro a dosis alimentarias.","detail":{"risks":"El disolvente que transporta la mayoría de los aromatizantes alimentarios líquidos. Se metaboliza a ácido láctico; el límite de la EFSA es generoso en comparación con la exposición alimentaria. Su mala fama proviene principalmente de usarse también en cigarrillos electrónicos y formulaciones anticongelantes; a dosis alimentarias carece de complicaciones.","benefits":"","interestingFact":"","research":""}}}`),n={methylparaben:{note:`Parabeno de cadena corta; el SCCS lo considera seguro en concentraciones ≤0.4%, pero es un mímico endocrino débil documentado.`},ethylparaben:{note:`Parabeno de cadena corta; permitido en la UE con límites de concentración.`},propylparaben:{note:`Parabeno de cadena más larga con mayor evidencia de actividad endocrina; concentración restringida en la UE.`},butylparaben:{note:`Parabeno de cadena más larga con la evidencia más sólida de actividad endocrina; restringido en la UE.`},isobutylparaben:{note:`Prohibido en cosméticos en la UE desde 2014.`},paraben:{note:`Conservante de la familia de los parabenos; el debate sobre su actividad endocrina varía según la longitud de la cadena.`},formaldehyde:{note:`Carcinógeno del Grupo 1 de la IARC; prohibido o fuertemente restringido en cosméticos en la UE.`},"dmdm hydantoin":{note:`Libera formaldehído lentamente; preocupación por sensibilización.`},"imidazolidinyl urea":{note:`Liberador de formaldehído; desencadenante común de alergia de contacto.`},"diazolidinyl urea":{note:`Liberador de formaldehído; desencadenante común de alergia de contacto.`},"quaternium-15":{note:`Potente liberador de formaldehído; prohibido en cosméticos en la UE desde 2022.`},"2-bromo-2-nitropropane-1,3-diol":{note:`Liberador de formaldehído; puede formar nitrosaminas con aminas.`},methylisothiazolinone:{note:`Alérgeno de contacto importante; prohibido en la UE en productos sin aclarado.`},methylchloroisothiazolinone:{note:`Sensibilizante potente; en la UE solo se permite en productos con aclarado bajo límites estrictos.`},triclosan:{note:`Preocupación por su actividad endocrina y resistencia a los antibióticos; restringido en la UE.`},phenoxyethanol:{note:`Ampliamente utilizado; el SCCS lo considera seguro en concentraciones ≤1%. Potencial de irritación leve.`},chlorphenesin:{note:`Conservante, irritante ocasional.`},"benzyl alcohol":{note:`Conservante y alérgeno de fragancia de declaración obligatoria.`},"sodium benzoate":{note:`Conservante suave y bien tolerado en dosis cosméticas.`},"potassium sorbate":{note:`Conservante suave y bien tolerado.`},"sodium lauryl sulfate":{note:`Limpiador eficaz; elimina los aceites naturales e irrita la piel y el cuero cabelludo sensibles.`},"ammonium lauryl sulfate":{note:`Tensioactivo de la clase SLS; perfil de irritación similar.`},"sodium laureth sulfate":{note:`Más suave que el SLS; posible presencia de trazas de 1,4-dioxano del proceso de fabricación.`},"cocamidopropyl betaine":{note:`Tensioactivo suave; se producen alergias causadas por impurezas.`},"cocamide dea":{note:`Grupo 2B de la IARC (posiblemente carcinógeno); prohibido en cosméticos en la UE.`},"cocamide mea":{note:`Posible formación de nitrosaminas con ciertos conservantes.`},triethanolamine:{note:`Ajustador de pH; preocupación por la formación de nitrosaminas en algunas fórmulas.`},"benzophenone-3":{note:`Evidencia de actividad endocrina; la UE redujo la concentración permitida en 2022. También es tóxico para los arrecifes.`},oxybenzone:{note:`Evidencia de actividad endocrina; restringido en la UE. También es tóxico para los arrecifes.`},"ethylhexyl methoxycinnamate":{note:`Actividad estrogénica en estudios; en fase de reducción gradual.`},octocrylene:{note:`Puede degradarse en benzofenona; reportes de fotoalergia.`},homosalate:{note:`El SCCS redujo la concentración segura debido a dudas sobre su actividad endocrina.`},"butyl methoxydibenzoylmethane":{note:`Filtro UVA ampliamente utilizado; la fotoestabilidad es el problema principal.`},"titanium dioxide":{note:`Seguro en la piel; evitar formas en aerosol inhalables (nano).`},"zinc oxide":{note:`Filtro UV mineral, bien tolerado.`},"polyethylene terephthalate":{note:`Solid synthetic polymer — intentionally added microplastic.`},polyethylene:{note:`Classic microbead polymer; EU restriction phasing in.`},polypropylene:{note:`Solid synthetic polymer — intentionally added microplastic.`},"polymethyl methacrylate":{note:`Acrylic microplastic used for texture.`},"nylon-12":{note:`Polyamide microplastic powder.`},"nylon-6":{note:`Polyamide microplastic powder.`},"acrylates copolymer":{note:`Film-forming polymer; counted as microplastic when solid.`},"acrylates crosspolymer":{note:`Film-forming polymer; counted as microplastic when solid.`},cyclopentasiloxane:{note:`EU-restricted in rinse-off (environmental persistence).`},cyclotetrasiloxane:{note:`EU-classified reprotoxic and persistent; restricted.`},dimethicone:{note:`Inert film-former; safe, though it can build up on hair.`},amodimethicone:{note:`Conditioning silicone, well tolerated.`},parfum:{note:`Undisclosed mixture — the most common cosmetic allergy source.`},fragrance:{note:`Undisclosed mixture — the most common cosmetic allergy source.`},limonene:{note:`Citrus fragrance component; declared EU allergen when oxidized.`},linalool:{note:`Floral fragrance component; declared EU allergen when oxidized.`},citronellol:{note:`Declared EU fragrance allergen.`},geraniol:{note:`Declared EU fragrance allergen.`},eugenol:{note:`Declared EU fragrance allergen.`},coumarin:{note:`Declared EU fragrance allergen.`},"hexyl cinnamal":{note:`Declared EU fragrance allergen.`},"benzyl salicylate":{note:`Declared EU fragrance allergen.`},"alcohol denat":{note:`Drying on skin at high concentration; fine low on the list.`},"propylene glycol":{note:`Humectant/solvent; occasional sensitivity.`},"peg-":{note:`Ethoxylated compound; trace 1,4-dioxane possible from manufacturing.`},"p-phenylenediamine":{note:`Potent sensitizer — the classic hair-dye allergy; EU-restricted.`},resorcinol:{note:`Hair-dye component with thyroid-activity evidence.`},hydroquinone:{note:`Skin-lightening agent banned in EU cosmetics.`},toluene:{note:`Neurotoxic solvent; banned in EU cosmetics.`},"salicylic acid":{note:`Exfoliating BHA; EU concentration limits, avoid in young children.`},retinol:{note:`Effective anti-aging active; EU limits concentration, avoid in pregnancy.`},"aluminum chlorohydrate":{note:`Antiperspirant salt; SCCS found current uses safe (2020).`},talc:{note:`Safe on skin if asbestos-free; avoid inhalable powder near lungs.`},"mineral oil":{note:`Occlusive; purity matters (cosmetic grade is refined).`},"paraffinum liquidum":{note:`Mineral oil by its INCI name; refined grades are safe.`},petrolatum:{note:`Oclusivo; seguro cuando está debidamente refinado (la EU lo exige).`},lanolin:{note:`Derivado de la lana; eficaz pero un alérgeno de contacto conocido.`},glycerin:{note:`Humectante que retiene la humedad; uno de los ingredientes más seguros en cosmética.`},"hyaluronic acid":{note:`Activo que retiene la humedad, muy bien tolerado.`},"sodium hyaluronate":{note:`Forma salina del ácido hialurónico; bien tolerado.`},panthenol:{note:`Provitamina B5 — genuinamente acondicionador y de bajo riesgo.`},niacinamide:{note:`Vitamina B3 — respaldada por la evidencia y bien tolerada.`},tocopherol:{note:`Antioxidante de vitamina E.`},ceramide:{note:`Lípidos idénticos a los de la piel; soporte para la barrera cutánea.`}},r={ui:e,additives:t,inci:n};export{t as additives,r as default,n as inci,e as ui};